import React, { useEffect, useRef } from 'react';
import * as d3 from 'd3';
import { DARTBOARD_NUMBERS, HEATMAP_COLORS } from '../constants';
import { Throw, Multiplier } from '../types';

interface DartboardHeatmapProps {
  history: Throw[];
  playerId: string;
  isDarkMode?: boolean;
}

export const DartboardHeatmap: React.FC<DartboardHeatmapProps> = ({ history, playerId, isDarkMode = false }) => {
  const svgRef = useRef<SVGSVGElement>(null);

  useEffect(() => {
    if (!svgRef.current) return;

    const width = 360;
    const height = 360;
    const margin = 10;
    // Radius logic
    const maxRadius = (Math.min(width, height) / 2) - margin;

    // Clear previous render
    d3.select(svgRef.current).selectAll('*').remove();

    const svg = d3
      .select(svgRef.current)
      .attr('viewBox', `0 0 ${width} ${height}`)
      .append('g')
      .attr('transform', `translate(${width / 2},${height / 2})`);

    // --- Dimensions based on standard proportions ---
    const rNumberRingOuter = maxRadius;
    const rNumberRingInner = maxRadius * 0.85;
    const rDoubleOuter = maxRadius * 0.85;
    const rDoubleInner = maxRadius * 0.80;
    const rTripleOuter = maxRadius * 0.50;
    const rTripleInner = maxRadius * 0.45;
    const rOuterBull = maxRadius * 0.10;
    const rInnerBull = maxRadius * 0.05;

    // Filter throws for this player
    // FIX: Include busted throws to show physical hits on the board
    const playerThrows = history.filter((t) => t.playerId === playerId);

    // Helper to get hit count
    const getHitCount = (scoreValue: number, multiplier: Multiplier): number => {
      return playerThrows.filter(
        (t) => t.scoreValue === scoreValue && t.multiplier === multiplier
      ).length;
    };

    // --- Ghost Board Colors Configuration ---
    // In Dark Mode, we need lighter ghost segments so "Black" hits are visible.
    // In Light Mode, we need darker ghost segments so "Pastel" hits are visible.
    const ghostColors = isDarkMode ? {
        dark: '#475569',  // Slate 600
        light: '#64748b', // Slate 500
        wire: '#334155'   // Slate 700 (Darker wire on light-ish board)
    } : {
        dark: '#64748b',  // Slate 500
        light: '#94a3b8', // Slate 400
        wire: '#e2e8f0'   // Slate 200
    };

    // Helper to get color
    const getSegmentColor = (scoreValue: number, multiplier: Multiplier, sliceIndex: number) => {
      const hits = getHitCount(scoreValue, multiplier);

      if (hits > 0) {
        // Clamp to max color key (6)
        const key = Math.min(hits, 6) as keyof typeof HEATMAP_COLORS;
        return HEATMAP_COLORS[key];
      }

      // GHOST BOARD LOOK
      // FIX: 20 (index 0) should be Dark. Even indices are Dark.
      const isDark = sliceIndex % 2 === 0;

      if (multiplier === Multiplier.Double || multiplier === Multiplier.Triple) {
        // Rings
        return isDark ? ghostColors.dark : ghostColors.light;
      }
      // Singles
      return isDark ? ghostColors.dark : ghostColors.light; 
    };

    const wireColor = ghostColors.wire;
    const wireWidth = 1;

    // 1. Draw Number Ring Background
    const arcNumberRing = d3.arc<any>()
      .innerRadius(rNumberRingInner)
      .outerRadius(rNumberRingOuter)
      .startAngle(0)
      .endAngle(2 * Math.PI);

    svg.append('path')
      .attr('d', arcNumberRing)
      .attr('fill', '#0f172a') // Slate 900 (Always dark for numbers)
      .attr('stroke', 'none');

    const sliceAngle = (2 * Math.PI) / 20;

    DARTBOARD_NUMBERS.forEach((num, i) => {
      // FIX: 20 is at top (0 degrees in D3 arc), so index 0 is at -slice/2 to +slice/2
      const startAngle = i * sliceAngle - sliceAngle / 2;
      const endAngle = startAngle + sliceAngle;

      // --- Draw Segments ---
      const drawArc = (innerR: number, outerR: number, mult: Multiplier) => {
         const arc = d3.arc<any>()
          .innerRadius(innerR)
          .outerRadius(outerR)
          .startAngle(startAngle)
          .endAngle(endAngle);

        svg.append('path')
          .attr('d', arc)
          .attr('fill', getSegmentColor(num, mult, i))
          .attr('stroke', wireColor)
          .attr('stroke-width', wireWidth);
      };

      // Outer Single
      drawArc(rTripleOuter, rDoubleInner, Multiplier.Single);

      // Inner Single
      drawArc(rOuterBull, rTripleInner, Multiplier.Single);

      // Double Ring
      drawArc(rDoubleInner, rDoubleOuter, Multiplier.Double);

      // Triple Ring
      drawArc(rTripleInner, rTripleOuter, Multiplier.Triple);

      // --- Draw Numbers ---
      const labelRadius = (rNumberRingInner + rNumberRingOuter) / 2;
      const angleDeg = (i * 360) / 20;

      svg.append('text')
        .attr('transform', `rotate(${angleDeg}) translate(0, -${labelRadius}) rotate(${-angleDeg})`)
        .attr('text-anchor', 'middle')
        .attr('dominant-baseline', 'central')
        .attr('fill', '#f8fafc')
        .attr('font-family', 'sans-serif')
        .attr('font-weight', 'bold')
        .attr('font-size', '16px')
        .text(String(num));
    });

    // --- Bullseye ---

    // Outer Bull (25) - Single
    const outerBullHits = getHitCount(25, Multiplier.Single);
    let outerBullColor = isDarkMode ? ghostColors.dark : ghostColors.light;
    if (outerBullHits > 0) {
        outerBullColor = HEATMAP_COLORS[Math.min(outerBullHits, 6) as keyof typeof HEATMAP_COLORS];
    }

    svg.append('circle')
      .attr('r', rOuterBull)
      .attr('fill', outerBullColor)
      .attr('stroke', wireColor)
      .attr('stroke-width', wireWidth);

    // Inner Bull (50) - Double
    const innerBullHits = getHitCount(25, Multiplier.Double);
    let innerBullColor = isDarkMode ? ghostColors.light : '#94a3b8'; // Slight contrast
    if (innerBullHits > 0) {
        innerBullColor = HEATMAP_COLORS[Math.min(innerBullHits, 6) as keyof typeof HEATMAP_COLORS];
    }

    svg.append('circle')
      .attr('r', rInnerBull)
      .attr('fill', innerBullColor)
      .attr('stroke', wireColor)
      .attr('stroke-width', wireWidth);

  }, [history, playerId, isDarkMode]);

  return <svg ref={svgRef} className="w-full max-w-[360px] h-auto mx-auto drop-shadow-xl" />;
};

import React, { useState, useEffect, useCallback } from 'react';
import { GameStatus, GameConfig, GameState, Player, Throw, Multiplier } from './types';
import { MAX_THROWS_PER_TURN, HEATMAP_COLORS } from './constants';
import { Setup } from './components/Setup';
import { Scoreboard } from './components/Scoreboard';
import { InputPad } from './components/InputPad';
import { DartboardHeatmap } from './components/DartboardHeatmap';

const App: React.FC = () => {
  const [isDarkMode, setIsDarkMode] = useState<boolean>(false);
  const [config, setConfig] = useState<GameConfig | null>(null);
  const [state, setState] = useState<GameState>({
    status: GameStatus.Setup,
    currentLeg: 1,
    currentPlayerIndex: 0,
    turnThrows: [],
    history: [],
    scoreAtStartOfTurn: 0,
  });
  const [players, setPlayers] = useState<Player[]>([]);
  const [winningThrow, setWinningThrow] = useState<Throw | null>(null);
  const [showBullAnimation, setShowBullAnimation] = useState<boolean>(false);
  const [showWinAnimation, setShowWinAnimation] = useState<boolean>(false);

  // Handle Dark Mode Toggle
  useEffect(() => {
    if (isDarkMode) {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  }, [isDarkMode]);

  const toggleTheme = () => setIsDarkMode(!isDarkMode);

  // --- AUDIO UTILS ---
  const playBustSound = () => {
    try {
      const AudioContext = window.AudioContext || (window as any).webkitAudioContext;
      if (!AudioContext) return;

      const ctx = new AudioContext();
      const osc = ctx.createOscillator();
      const gain = ctx.createGain();

      // Sawtooth wave for a buzzy sound
      osc.type = 'sawtooth';

      // Pitch drops from 150Hz to 40Hz (Buzzer effect)
      osc.frequency.setValueAtTime(150, ctx.currentTime);
      osc.frequency.exponentialRampToValueAtTime(40, ctx.currentTime + 0.4);

      // Volume envelope
      gain.gain.setValueAtTime(0.3, ctx.currentTime);
      gain.gain.exponentialRampToValueAtTime(0.01, ctx.currentTime + 0.4);

      osc.connect(gain);
      gain.connect(ctx.destination);

      osc.start();
      osc.stop(ctx.currentTime + 0.4);
    } catch (e) {
      console.error("Audio playback failed", e);
    }
  };

  const startGame = (newConfig: GameConfig) => {
    setConfig(newConfig);
    setPlayers(newConfig.players);
    setState({
      status: GameStatus.Playing,
      currentLeg: 1,
      currentPlayerIndex: 0,
      turnThrows: [],
      history: [],
      scoreAtStartOfTurn: newConfig.players[0].score,
    });
    setWinningThrow(null);
    setShowWinAnimation(false);
  };

  const handleTurnEnd = useCallback(() => {
    if (!config) return;

    setState((prev) => {
        const nextPlayerIndex = (prev.currentPlayerIndex + 1) % players.length;
        const nextPlayer = players[nextPlayerIndex];

        return {
            ...prev,
            turnThrows: [],
            currentPlayerIndex: nextPlayerIndex,
            scoreAtStartOfTurn: nextPlayer.score, // Snapshot for next player
        };
    });
  }, [config, players]);

  const handleThrow = (value: number, multiplier: Multiplier) => {
    if (state.status !== GameStatus.Playing || !config) return;

    // --- Animation Trigger ---
    if (value === 25) {
      setShowBullAnimation(true);
      setTimeout(() => setShowBullAnimation(false), 1200); // Matches CSS animation duration
    }
    // -------------------------

    const currentPlayer = players[state.currentPlayerIndex];
    const points = value * multiplier;
    const newScore = currentPlayer.score - points;
    const now = Date.now();

    let isBust = false;
    let isWin = false;

    // Win/Bust Logic
    if (newScore < 0) {
      isBust = true;
    } else if (newScore === 0) {
      // Validate double out rule if necessary (standard is double out)
      // For this simplified version, hitting exactly 0 is a win.
      // If we wanted double out: if (multiplier === Multiplier.Double || value === 50) ...
      isWin = true;
    }

    const newThrow: Throw = {
      playerId: currentPlayer.id,
      legId: state.currentLeg,
      scoreValue: value,
      multiplier,
      totalPoints: points,
      isBust,
      isWin,
      timestamp: now,
    };

    // Update Players State
    const updatedPlayers = [...players];
    if (isBust) {
      // Reset to start of turn
      updatedPlayers[state.currentPlayerIndex].score = state.scoreAtStartOfTurn;
      playBustSound(); // PLAY SOUND
    } else {
      updatedPlayers[state.currentPlayerIndex].score = newScore;
    }
    setPlayers(updatedPlayers);

    // Update Game State
    setState((prev) => {
      const newTurnThrows = [...prev.turnThrows, newThrow];
      const newHistory = [...prev.history, newThrow];

      return {
        ...prev,
        turnThrows: newTurnThrows,
        history: newHistory,
      };
    });

    // Check immediate transitions
    if (isWin) {
      setWinningThrow(newThrow);

      // Increment win count
      const winnerUpdate = [...updatedPlayers];
      winnerUpdate[state.currentPlayerIndex].wins += 1;
      setPlayers(winnerUpdate);

      // Trigger Win Animation
      setShowWinAnimation(true);

      // Delay showing the summary screen to let animation play
      setTimeout(() => {
        setState((prev) => ({ ...prev, status: GameStatus.Summary }));
        setShowWinAnimation(false);
      }, 2500);
      return;
    }

    if (isBust) {
      // Bust ends turn immediately
      setTimeout(handleTurnEnd, 800); 
      return;
    }

    // Standard turn progression
    if (state.turnThrows.length + 1 >= MAX_THROWS_PER_TURN) {
      setTimeout(handleTurnEnd, 500);
    }
  };

  const handleUndo = () => {
    if (state.turnThrows.length === 0) return; 

    const lastThrow = state.turnThrows[state.turnThrows.length - 1];

    // Revert Player Score
    const updatedPlayers = [...players];
    const player = updatedPlayers[state.currentPlayerIndex];

    if (lastThrow.isBust) {
        const pointsFromPrevThrows = state.turnThrows
            .slice(0, -1)
            .reduce((acc, t) => acc + t.totalPoints, 0);
        player.score = state.scoreAtStartOfTurn - pointsFromPrevThrows;
    } else {
        player.score += lastThrow.totalPoints;
    }
    setPlayers(updatedPlayers);

    // Revert State
    setState((prev) => ({
        ...prev,
        turnThrows: prev.turnThrows.slice(0, -1),
        history: prev.history.slice(0, -1),
    }));
  };

  const restartGame = () => {
    if (!config) return;

    // Rematch Logic: Keep the current player roster (with wins) but reset scores
    const nextLegPlayers = players.map(p => ({
        ...p,
        score: config.startingScore // Reset score to 301/501
    }));

    const rematchConfig = {
        ...config,
        players: nextLegPlayers
    };

    startGame(rematchConfig);
  };

  const newGame = () => {
    setState((prev) => ({ ...prev, status: GameStatus.Setup }));
  };

  // --- Theme Toggle Button ---
  const ThemeToggle = () => (
    <button 
        onClick={toggleTheme}
        className="p-2 rounded-full bg-slate-200 dark:bg-slate-800 text-slate-600 dark:text-slate-300 hover:bg-slate-300 dark:hover:bg-slate-700 transition-colors"
        title="Toggle Theme"
    >
        {isDarkMode ? '🌙' : '☀️'}
    </button>
  );

  // --- RENDER ---

  if (state.status === GameStatus.Setup) {
    return (
        <div className="min-h-screen bg-slate-50 dark:bg-slate-950 text-slate-800 dark:text-slate-100 p-4 flex flex-col items-center justify-center transition-colors duration-300">
            <div className="absolute top-4 right-4">
                <ThemeToggle />
            </div>
            <Setup onStartGame={startGame} />
        </div>
    );
  }

  if (state.status === GameStatus.Summary) {
    const winner = players[state.currentPlayerIndex];
    return (
      <div className="min-h-screen bg-slate-50 dark:bg-slate-950 text-slate-800 dark:text-slate-100 p-4 transition-colors duration-300">
        <div className="absolute top-4 right-4">
            <ThemeToggle />
        </div>
        <div className="max-w-4xl mx-auto">
            <div className="text-center mb-8">
                <h1 className="text-5xl font-black text-emerald-500 mb-2">GAME SHOT!</h1>
                <p className="text-2xl text-slate-600 dark:text-slate-400">{winner.name} wins the leg.</p>
                <div className="mt-6 flex justify-center gap-4">
                    <button onClick={restartGame} className="bg-emerald-500 hover:bg-emerald-600 text-white shadow-lg shadow-emerald-200 dark:shadow-emerald-900/50 px-8 py-3 rounded-xl font-bold transition-all transform hover:-translate-y-1">Rematch</button>
                    <button onClick={newGame} className="bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-700 text-slate-700 dark:text-slate-200 hover:bg-slate-50 dark:hover:bg-slate-700 shadow-sm px-6 py-3 rounded-xl font-bold transition-all">New Setup</button>
                </div>
            </div>

            <div className="grid md:grid-cols-2 gap-8">
                {players.map(p => (
                    <div key={p.id} className="bg-white dark:bg-slate-800 p-6 rounded-2xl shadow-sm border border-slate-100 dark:border-slate-700">
                        <div className="flex justify-between items-center mb-4">
                            <h3 className="text-xl font-bold text-slate-700 dark:text-slate-300">{p.name}</h3>
                            <span className="text-sm font-semibold bg-slate-100 dark:bg-slate-700 px-2 py-1 rounded text-slate-500 dark:text-slate-400">Avg: {Math.round((config?.startingScore! - p.score) / (state.history.filter(t => t.playerId === p.id).length / 3) || 0)}</span>
                        </div>
                        <div className="flex justify-center mb-4">
                             <DartboardHeatmap history={state.history} playerId={p.id} isDarkMode={isDarkMode} />
                        </div>
                        <div className="flex flex-wrap justify-center gap-2 text-xs">
                             {Object.entries(HEATMAP_COLORS).map(([count, color]) => {
                                if (count === '0') return null;
                                return (
                                    <div key={count} className="flex items-center gap-1 bg-slate-50 dark:bg-slate-700 border border-slate-100 dark:border-slate-600 px-2 py-1 rounded">
                                        <div className="w-3 h-3 rounded-full border border-black/10" style={{ backgroundColor: color }}></div>
                                        <span className="text-slate-600 dark:text-slate-300">{parseInt(count) >= 6 ? '6+' : count}</span>
                                    </div>
                                );
                             })}
                        </div>
                    </div>
                ))}
            </div>
        </div>
      </div>
    );
  }

  const currentPlayer = players[state.currentPlayerIndex];

  return (
    <div className="min-h-screen bg-slate-50 dark:bg-slate-950 text-slate-800 dark:text-slate-100 p-4 flex flex-col transition-colors duration-300 relative overflow-hidden">

      {/* BULL ANIMATION OVERLAY */}
      {showBullAnimation && (
        <div className="fixed inset-0 z-50 flex items-center justify-center pointer-events-none">
            <div className="absolute inset-0 bg-white/20 dark:bg-black/20 backdrop-blur-sm animate-fade-in"></div>
            <div className="animate-bull-blast origin-center relative">
                 <div className="bg-red-600 text-white font-black text-6xl md:text-8xl px-12 py-8 rounded-[3rem] shadow-2xl border-8 border-white dark:border-slate-800 transform rotate-3 whitespace-nowrap tracking-tighter">
                    BULL!
                </div>
            </div>
        </div>
      )}

      {/* WINNER ANIMATION OVERLAY */}
      {showWinAnimation && (
        <div className="fixed inset-0 z-[60] flex items-center justify-center overflow-hidden pointer-events-none">
            <div className="absolute inset-0 bg-emerald-500/90 dark:bg-emerald-900/90 backdrop-blur-md"></div>
            {/* Confetti Generation */}
            {[...Array(20)].map((_, i) => (
                <div 
                    key={i} 
                    className="confetti" 
                    style={{
                        left: `${Math.random() * 100}%`,
                        backgroundColor: ['#fbbf24', '#f87171', '#34d399', '#60a5fa'][Math.floor(Math.random() * 4)],
                        animationDelay: `${Math.random() * 2}s`,
                        animationDuration: `${2 + Math.random() * 3}s`
                    }}
                ></div>
            ))}

            <div className="animate-winner-pop text-center relative z-10">
                <h2 className="text-4xl font-bold text-white mb-4 uppercase tracking-widest opacity-80">Winner</h2>
                <div className="bg-white text-emerald-600 font-black text-6xl md:text-9xl px-12 py-6 rounded-3xl shadow-2xl transform -rotate-2 whitespace-nowrap tracking-tighter">
                    {players[state.currentPlayerIndex].name}
                </div>
                <div className="mt-8 text-white text-2xl font-bold animate-pulse">Game Shot!</div>
            </div>
        </div>
      )}

      <header className="flex justify-between items-center mb-4 max-w-md mx-auto w-full relative z-10">
        <h1 className="font-bold text-slate-400 dark:text-slate-500 tracking-wider uppercase text-sm">Leg {state.currentLeg}</h1>
        <div className="flex items-center gap-4">
            <ThemeToggle />
            <button onClick={newGame} className="text-xs text-slate-500 dark:text-slate-400 hover:text-slate-700 dark:hover:text-slate-200 font-medium">Quit</button>
        </div>
      </header>

      <main className="flex-1 flex flex-col justify-center relative z-10">
        <Scoreboard 
            players={players} 
            currentPlayerId={currentPlayer.id}
            currentTurnThrows={state.turnThrows}
            scoreAtStartOfTurn={state.scoreAtStartOfTurn}
        />

        <InputPad 
            onSubmitThrow={handleThrow} 
            onUndo={handleUndo}
            canUndo={state.turnThrows.length > 0}
        />
      </main>
    </div>
  );
};

export default App;

export enum Multiplier {
  Single = 1,
  Double = 2,
  Triple = 3,
}

export interface Throw {
  playerId: string;
  legId: number;
  scoreValue: number; // The raw number (e.g., 20)
  multiplier: Multiplier;
  totalPoints: number; // value * multiplier
  isBust: boolean;
  isWin: boolean;
  timestamp: number;
}

export interface Player {
  id: string;
  name: string;
  score: number;
  wins: number;
}

export enum GameStatus {
  Setup,
  Playing,
  Summary,
}

export interface GameConfig {
  startingScore: number;
  totalLegs: number;
  players: Player[];
}

export interface GameState {
  status: GameStatus;
  currentLeg: number;
  currentPlayerIndex: number;
  legStarterIndex: number; // Index of the player who started the current leg
  turnThrows: Throw[]; // Throws in the current turn (max 3)
  history: Throw[]; // All throws in the game
  scoreAtStartOfTurn: number;
}

import React, { useState } from 'react';
import { GameConfig, Player } from '../types';

interface SetupProps {
  onStartGame: (config: GameConfig) => void;
}

export const Setup: React.FC<SetupProps> = ({ onStartGame }) => {
  const [score, setScore] = useState<number>(501);
  const [legs, setLegs] = useState<number>(3); // Default to Best of 3
  const [playerNames, setPlayerNames] = useState<string[]>(['Player 1', 'Player 2']);

  const addPlayer = () => {
    if (playerNames.length < 8) {
      setPlayerNames([...playerNames, `Player ${playerNames.length + 1}`]);
    }
  };

  const removePlayer = (index: number) => {
    if (playerNames.length > 1) {
      const newNames = playerNames.filter((_, i) => i !== index);
      setPlayerNames(newNames);
    }
  };

  const updateName = (index: number, name: string) => {
    const newNames = [...playerNames];
    newNames[index] = name;
    setPlayerNames(newNames);
  };

  const handleStart = () => {
    const players: Player[] = playerNames.map((name, index) => ({
      id: `p${index}-${Date.now()}`,
      name: name.trim() || `Player ${index + 1}`,
      score: score,
      wins: 0,
    }));

    onStartGame({
      startingScore: score,
      totalLegs: legs,
      players,
    });
  };

  return (
    <div className="max-w-md w-full mx-auto p-6 bg-white dark:bg-slate-800 rounded-2xl shadow-xl border border-slate-100 dark:border-slate-700 transition-colors">
      <h1 className="text-3xl font-bold text-center text-emerald-500 mb-8 tracking-tight">New Game</h1>

      {/* Score Selection */}
      <div className="mb-6">
        <label className="block text-slate-500 dark:text-slate-400 mb-2 text-xs uppercase font-bold tracking-wider">Starting Score</label>
        <div className="flex gap-3">
          {[301, 501].map((val) => (
            <button
              key={val}
              onClick={() => setScore(val)}
              className={`flex-1 py-3 rounded-xl font-bold transition-all shadow-sm ${
                score === val 
                  ? 'bg-emerald-500 text-white shadow-emerald-200 dark:shadow-emerald-900/50 ring-2 ring-emerald-500 ring-offset-1 dark:ring-offset-slate-800' 
                  : 'bg-white dark:bg-slate-700 border border-slate-200 dark:border-slate-600 text-slate-600 dark:text-slate-300 hover:bg-slate-50 dark:hover:bg-slate-600'
              }`}
            >
              {val}
            </button>
          ))}
          <input
            type="number"
            value={score}
            onChange={(e) => setScore(parseInt(e.target.value) || 0)}
            className="w-24 bg-slate-50 dark:bg-slate-700 border border-slate-200 dark:border-slate-600 rounded-xl px-3 text-center text-slate-800 dark:text-white font-semibold focus:outline-none focus:ring-2 focus:ring-emerald-500 focus:bg-white dark:focus:bg-slate-600 transition-all shadow-inner"
            placeholder="Custom"
          />
        </div>
      </div>

      {/* Legs */}
      <div className="mb-6">
        <label className="block text-slate-500 dark:text-slate-400 mb-2 text-xs uppercase font-bold tracking-wider">Format (Best of X Legs)</label>
        <div className="flex items-center bg-slate-50 dark:bg-slate-700 rounded-xl p-1 border border-slate-200 dark:border-slate-600 shadow-inner">
          <button 
            onClick={() => setLegs(Math.max(1, legs - 2))} // Jump by 2 (1, 3, 5...) generally preferred
            className="w-12 h-10 flex items-center justify-center text-slate-400 dark:text-slate-500 hover:text-emerald-600 dark:hover:text-emerald-400 hover:bg-white dark:hover:bg-slate-600 rounded-lg transition-all font-bold"
          >
            -
          </button>
          <div className="flex-1 text-center font-bold text-xl text-slate-700 dark:text-slate-200">
            {legs} <span className="text-sm text-slate-400 font-normal">(First to {Math.ceil(legs/2)})</span>
          </div>
          <button 
            onClick={() => setLegs(legs + 2)}
            className="w-12 h-10 flex items-center justify-center text-slate-400 dark:text-slate-500 hover:text-emerald-600 dark:hover:text-emerald-400 hover:bg-white dark:hover:bg-slate-600 rounded-lg transition-all font-bold"
          >
            +
          </button>
        </div>
      </div>

      {/* Players */}
      <div className="mb-8">
        <label className="block text-slate-500 dark:text-slate-400 mb-2 text-xs uppercase font-bold tracking-wider">Players</label>
        <div className="space-y-3 max-h-60 overflow-y-auto pr-1 custom-scrollbar">
          {playerNames.map((name, index) => (
            <div key={index} className="flex gap-2 group">
              <input
                type="text"
                value={name}
                onChange={(e) => updateName(index, e.target.value)}
                className="flex-1 bg-slate-50 dark:bg-slate-700 border border-slate-200 dark:border-slate-600 rounded-xl px-4 py-3 text-slate-800 dark:text-slate-100 font-medium focus:outline-none focus:ring-2 focus:ring-emerald-500 focus:bg-white dark:focus:bg-slate-600 transition-all shadow-sm"
                placeholder={`Player ${index + 1}`}
              />
              {playerNames.length > 1 && (
                <button
                  onClick={() => removePlayer(index)}
                  className="w-12 flex items-center justify-center text-slate-300 dark:text-slate-500 hover:text-red-500 hover:bg-red-50 dark:hover:bg-red-900/20 rounded-xl transition-colors"
                >
                  ✕
                </button>
              )}
            </div>
          ))}
        </div>
        {playerNames.length < 8 && (
          <button
            onClick={addPlayer}
            className="mt-3 w-full py-3 border-2 border-dashed border-slate-200 dark:border-slate-600 text-slate-400 dark:text-slate-500 rounded-xl hover:border-emerald-300 dark:hover:border-emerald-700 hover:text-emerald-500 dark:hover:text-emerald-400 hover:bg-emerald-50 dark:hover:bg-emerald-900/10 transition-all text-sm font-bold tracking-wide"
          >
            + Add Player
          </button>
        )}
      </div>

      <button
        onClick={handleStart}
        className="w-full bg-emerald-500 hover:bg-emerald-600 text-white font-bold py-4 rounded-xl shadow-lg shadow-emerald-200 dark:shadow-emerald-900/50 transform transition hover:-translate-y-1 active:translate-y-0"
      >
        GAME ON!
      </button>
    </div>
  );
};

import React, { useState, useEffect, useCallback } from 'react';
import { GameStatus, GameConfig, GameState, Player, Throw, Multiplier } from './types';
import { MAX_THROWS_PER_TURN, HEATMAP_COLORS } from './constants';
import { Setup } from './components/Setup';
import { Scoreboard } from './components/Scoreboard';
import { InputPad } from './components/InputPad';
import { DartboardHeatmap } from './components/DartboardHeatmap';

const App: React.FC = () => {
  const [isDarkMode, setIsDarkMode] = useState<boolean>(false);
  const [config, setConfig] = useState<GameConfig | null>(null);
  const [state, setState] = useState<GameState>({
    status: GameStatus.Setup,
    currentLeg: 1,
    currentPlayerIndex: 0,
    legStarterIndex: 0,
    turnThrows: [],
    history: [],
    scoreAtStartOfTurn: 0,
  });
  const [players, setPlayers] = useState<Player[]>([]);
  const [winningThrow, setWinningThrow] = useState<Throw | null>(null);
  const [showBullAnimation, setShowBullAnimation] = useState<boolean>(false);
  const [showWinAnimation, setShowWinAnimation] = useState<boolean>(false);

  // Handle Dark Mode Toggle
  useEffect(() => {
    if (isDarkMode) {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  }, [isDarkMode]);

  const toggleTheme = () => setIsDarkMode(!isDarkMode);

  // --- AUDIO UTILS ---
  const playBustSound = () => {
    try {
      const AudioContext = window.AudioContext || (window as any).webkitAudioContext;
      if (!AudioContext) return;

      const ctx = new AudioContext();
      const osc = ctx.createOscillator();
      const gain = ctx.createGain();

      // Sawtooth wave for a buzzy sound
      osc.type = 'sawtooth';

      // Pitch drops from 150Hz to 40Hz (Buzzer effect)
      osc.frequency.setValueAtTime(150, ctx.currentTime);
      osc.frequency.exponentialRampToValueAtTime(40, ctx.currentTime + 0.4);

      // Volume envelope
      gain.gain.setValueAtTime(0.3, ctx.currentTime);
      gain.gain.exponentialRampToValueAtTime(0.01, ctx.currentTime + 0.4);

      osc.connect(gain);
      gain.connect(ctx.destination);

      osc.start();
      osc.stop(ctx.currentTime + 0.4);
    } catch (e) {
      console.error("Audio playback failed", e);
    }
  };

  const startGame = (newConfig: GameConfig) => {
    setConfig(newConfig);
    setPlayers(newConfig.players);
    setState({
      status: GameStatus.Playing,
      currentLeg: 1,
      currentPlayerIndex: 0,
      legStarterIndex: 0,
      turnThrows: [],
      history: [],
      scoreAtStartOfTurn: newConfig.players[0].score,
    });
    setWinningThrow(null);
    setShowWinAnimation(false);
  };

  const handleTurnEnd = useCallback(() => {
    if (!config) return;

    setState((prev) => {
        const nextPlayerIndex = (prev.currentPlayerIndex + 1) % players.length;
        const nextPlayer = players[nextPlayerIndex];

        return {
            ...prev,
            turnThrows: [],
            currentPlayerIndex: nextPlayerIndex,
            scoreAtStartOfTurn: nextPlayer.score, // Snapshot for next player
        };
    });
  }, [config, players]);

  const handleThrow = (value: number, multiplier: Multiplier) => {
    if (state.status !== GameStatus.Playing || !config) return;

