    try {
      const AudioContext = window.AudioContext || (window as any).webkitAudioContext;
      if (!AudioContext) return;

      const ctx = new AudioContext();

      // Create two oscillators to make a dissonant "buzzer" sound
      const osc1 = ctx.createOscillator();
      const osc2 = ctx.createOscillator();
      const gain = ctx.createGain();

      // Sawtooth and Square waves are harsh
      osc1.type = 'sawtooth';
      osc2.type = 'square';

      // Low, dissonant frequencies (typical game show buzzer)
      osc1.frequency.setValueAtTime(120, ctx.currentTime);
      osc2.frequency.setValueAtTime(126, ctx.currentTime); // Slight detune for roughness

      // Volume envelope: hard attack, sustain, quick release
      gain.gain.setValueAtTime(0.2, ctx.currentTime);
      gain.gain.setValueAtTime(0.2, ctx.currentTime + 0.4);
      gain.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + 0.5);

      osc1.connect(gain);
      osc2.connect(gain);
      gain.connect(ctx.destination);

      osc1.start();
      osc2.start();

      const duration = 0.5;
      osc1.stop(ctx.currentTime + duration);
      osc2.stop(ctx.currentTime + duration);
