        <div className="flex gap-3">
          {[301, 501].map((val) => (
            <button
              key={val}
              onClick={() => setScore(val)}
              className={`flex-1 py-3 rounded-2xl font-bold transition-all ${
                score === val 
                  ? 'bg-emerald-500 text-white shadow-lg shadow-emerald-200 dark:shadow-emerald-900/30' 
                  : 'bg-slate-50 dark:bg-slate-700/50 text-slate-500 dark:text-slate-400 hover:bg-slate-100 dark:hover:bg-slate-700'
              }`}
            >
              {val}
            </button>
          ))}
          <input
            type="number"
            value={score}
            onChange={(e) => setScore(parseInt(e.target.value) || 0)}
            className="w-20 bg-slate-50 dark:bg-slate-700/50 rounded-2xl px-2 text-center text-slate-800 dark:text-white font-bold focus:outline-none focus:ring-2 focus:ring-emerald-500 transition-all"
            placeholder="Custom"
          />
        </div>
      </div>

      {/* Legs */}
      <div className="mb-6">
        <label className="block text-slate-400 dark:text-slate-500 mb-2 text-[10px] uppercase font-black tracking-[0.2em]">Format (Best of X)</label>
        <div className="flex items-center bg-slate-50 dark:bg-slate-700/50 rounded-2xl p-1">
          <button 
            onClick={() => setLegs(Math.max(1, legs - 2))}
            className="w-12 h-11 flex items-center justify-center text-slate-400 hover:text-emerald-500 transition-colors text-2xl"
          >
            -
          </button>
          <div className="flex-1 text-center font-black text-xl text-slate-800 dark:text-slate-100">
            {legs} <span className="text-[10px] text-slate-400 font-bold uppercase ml-1">Legs</span>
          </div>
          <button 
            onClick={() => setLegs(legs + 2)}
            className="w-12 h-11 flex items-center justify-center text-slate-400 hover:text-emerald-500 transition-colors text-2xl"
          >
            +
          </button>
        </div>
      </div>

      {/* Players */}
      <div className="mb-8">
        <div className="flex justify-between items-center mb-3">
            <label className="text-slate-400 dark:text-slate-500 text-[10px] uppercase font-black tracking-[0.2em]">Player Order</label>
            {playerNames.length > 1 && (
                <button 
                    onClick={shufflePlayers}
                    className="text-[10px] text-emerald-500 hover:text-emerald-600 font-black tracking-widest uppercase transition-colors"
