      const AudioContext = window.AudioContext || (window as any).webkitAudioContext;
      if (!AudioContext) return;
      const ctx = new AudioContext();
      const gain = ctx.createGain();
      gain.connect(ctx.destination);
      gain.gain.setValueAtTime(0.1, ctx.currentTime);

      const playNote = (freq: number, start: number, duration: number) => {
        const osc = ctx.createOscillator();
        osc.type = 'sine';
        osc.frequency.setValueAtTime(freq, ctx.currentTime + start);
        const noteGain = ctx.createGain();
        noteGain.gain.setValueAtTime(0, ctx.currentTime + start);
        noteGain.gain.linearRampToValueAtTime(0.2, ctx.currentTime + start + 0.05);
        noteGain.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + start + duration);
        osc.connect(noteGain);
        noteGain.connect(gain);
        osc.start(ctx.currentTime + start);
        osc.stop(ctx.currentTime + start + duration);
      };

      const now = 0;
      playNote(523.25, now, 0.4); 
      playNote(659.25, now + 0.15, 0.4); 
      playNote(783.99, now + 0.3, 0.4); 
      playNote(1046.50, now + 0.45, 1.2); 
    } catch (e) { console.error("Audio failed", e); }
  };

  const startGame = (newConfig: GameConfig) => {
    setConfig(newConfig);
    setPlayers(newConfig.players);
    setState({
      status: GameStatus.Playing,
      currentLeg: 1,
      currentPlayerIndex: 0,
      legStarterIndex: 0,
      turnThrows: [],
      history: [],
      scoreAtStartOfTurn: newConfig.players[0].score,
    });
    setWinningThrow(null);
    setShowWinAnimation(false);
  };

  const handleTurnEnd = useCallback((playersSnapshot?: Player[]) => {
    if (!config) return;
    const currentPlayers = playersSnapshot || players;
    setState((prev) => {
        const nextPlayerIndex = (prev.currentPlayerIndex + 1) % currentPlayers.length;
        const nextPlayer = currentPlayers[nextPlayerIndex];
        return {
            ...prev,
            turnThrows: [],
            currentPlayerIndex: nextPlayerIndex,
            scoreAtStartOfTurn: nextPlayer.score,
        };
    });
  }, [config, players]);

  const handleThrow = (value: number, multiplier: Multiplier) => {
    if (state.status !== GameStatus.Playing || !config || showWinAnimation) return;

    if (value === 25) {
      if (multiplier === Multiplier.Double) {
        setShowDoubleBullAnimation(true);
        setTimeout(() => setShowDoubleBullAnimation(false), 1500);
      } else {
        setShowBullAnimation(true);
        setTimeout(() => setShowBullAnimation(false), 1200);
      }
    }

    const currentPlayer = players[state.currentPlayerIndex];
    const points = value * multiplier;
    const newScore = currentPlayer.score - points;
    const now = Date.now();

    let isBust = false;
    let isWin = false;

    if (newScore < 0) {
      isBust = true;
    } else if (newScore === 0) {
      isWin = true;
    }

    const newThrow: Throw = {
      playerId: currentPlayer.id,
      legId: state.currentLeg,
      scoreValue: value,
      multiplier,
      totalPoints: points,
      isBust,
      isWin,
      timestamp: now,
    };

    const updatedPlayers = [...players];
    if (isBust) {
      updatedPlayers[state.currentPlayerIndex].score = state.scoreAtStartOfTurn;
      playBustSound();
    } else {
      updatedPlayers[state.currentPlayerIndex].score = newScore;
    }
    setPlayers(updatedPlayers);

    setState((prev) => {
      const newTurnThrows = [...prev.turnThrows, newThrow];
      const newHistory = [...prev.history, newThrow];
      return {
        ...prev,
        turnThrows: newTurnThrows,
        history: newHistory,
      };
    });

    if (isWin) {
      setWinningThrow(newThrow);
      const winnerUpdate = [...updatedPlayers];
      winnerUpdate[state.currentPlayerIndex].wins += 1;
      setPlayers(winnerUpdate);
      setShowWinAnimation(true);
      playWinSound(); 

      setTimeout(() => {
        setState((prev) => ({ ...prev, status: GameStatus.Summary }));
        setShowWinAnimation(false);
      }, 2500);
      return;
    }

    if (isBust) {
      setTimeout(() => handleTurnEnd(updatedPlayers), 800); 
      return;
    }

    if (state.turnThrows.length + 1 >= MAX_THROWS_PER_TURN) {
      setTimeout(() => handleTurnEnd(updatedPlayers), 500);
    }
  };

  const handleUndo = () => {
    if (state.history.length === 0 || !config) return;

    const newHistory = [...state.history];
    const undoneThrow = newHistory.pop();
    if (!undoneThrow) return;

    // 1. Identify affected player and leg
    const playerIndex = players.findIndex(p => p.id === undoneThrow.playerId);
    if (playerIndex === -1) return;

    // 2. Recalculate all players scores to be safe
    // We only care about the player who made the last throw
    const updatedPlayers = players.map(player => {
        // Find all non-bust throws for this player in current leg from the NEW history
        const playerLegThrows = newHistory.filter(t => t.playerId === player.id && t.legId === state.currentLeg);

        // Find if there was a bust recently. A bust resets score to turn-start score.
        // The most accurate way is to replay history for this player in this leg.
        let currentScore = config.startingScore;
        let scoreAtTurnStart = config.startingScore;
        let turnDartCount = 0;

        for (const t of playerLegThrows) {
            if (turnDartCount === 0) scoreAtTurnStart = currentScore;

            if (t.isBust) {
                currentScore = scoreAtTurnStart;
                turnDartCount = 0;
            } else {
                currentScore -= t.totalPoints;
                turnDartCount++;
                if (turnDartCount >= MAX_THROWS_PER_TURN) turnDartCount = 0;
            }
        }

        return { ...player, score: currentScore, wins: player.id === undoneThrow.playerId && undoneThrow.isWin ? player.wins - 1 : player.wins };
    });

    setPlayers(updatedPlayers);

    // 3. Reconstruct the turn for the player we just undid
    const playerNewHistory = newHistory.filter(t => t.playerId === undoneThrow.playerId && t.legId === state.currentLeg);

    // Find the last "turn start" for this player
    // A turn starts if:
    // - It's the beginning of the leg
    // - The previous throw was the 3rd of a turn
    // - The previous throw was a bust
    const lastTurnThrows: Throw[] = [];
    let turnCount = 0;
    for (const t of playerNewHistory) {
        lastTurnThrows.push(t);
        turnCount++;
        if (turnCount >= MAX_THROWS_PER_TURN || t.isBust) {
            lastTurnThrows.length = 0; // Clear, we only want the UNFINISHED turn at the end
            turnCount = 0;
        }
    }

    // 4. Calculate scoreAtStartOfTurn for the target player
    const pointsInCurrentUnfinishedTurn = lastTurnThrows.reduce((sum, t) => sum + t.totalPoints, 0);
    const scoreAtStartOfTurn = updatedPlayers[playerIndex].score + pointsInCurrentUnfinishedTurn;

    setState((prev) => ({
        ...prev,
        status: GameStatus.Playing, // Back to playing if we were in summary
        currentPlayerIndex: playerIndex,
        turnThrows: lastTurnThrows,
        history: newHistory,
        scoreAtStartOfTurn: scoreAtStartOfTurn,
    }));

    setWinningThrow(null);
  };

  const targetWins = config ? Math.ceil(config.totalLegs / 2) : 1;
  const isMatchOver = players.some(p => p.wins >= targetWins);

  const startNextLeg = () => {
    if (!config) return;
    const nextLegPlayers = players.map(p => ({ ...p, score: config.startingScore }));
    setPlayers(nextLegPlayers);
    const nextStarterIndex = (state.legStarterIndex + 1) % players.length;
    setState(prev => ({
        ...prev,
        status: GameStatus.Playing,
        currentLeg: prev.currentLeg + 1,
        currentPlayerIndex: nextStarterIndex,
        legStarterIndex: nextStarterIndex,
        turnThrows: [],
        scoreAtStartOfTurn: config.startingScore,
    }));
    setWinningThrow(null);
    setShowWinAnimation(false);
  };

  const restartMatch = () => {
    if (!config) return;
    const resetPlayers = players.map(p => ({ ...p, score: config.startingScore, wins: 0 }));
    const matchConfig = { ...config, players: resetPlayers };
    startGame(matchConfig);
  };

  const newGame = () => setState((prev) => ({ ...prev, status: GameStatus.Setup }));

  const ThemeToggle = () => (
    <button 
        onClick={toggleTheme}
        className="p-2 rounded-full bg-slate-200 dark:bg-slate-800 text-slate-600 dark:text-slate-300 hover:bg-slate-300 dark:hover:bg-slate-700 transition-colors"
        title="Toggle Theme"
    >
        {isDarkMode ? '🌙' : '☀️'}
    </button>
  );

  if (state.status === GameStatus.Setup) {
    return (
        <div className="min-h-screen bg-slate-50 dark:bg-slate-950 text-slate-800 dark:text-slate-100 p-4 flex flex-col items-center justify-center transition-colors duration-300">
            <div className="absolute top-4 right-4"><ThemeToggle /></div>
            <Setup onStartGame={startGame} />
        </div>
    );
  }

  if (state.status === GameStatus.Summary) {
    const winner = players[state.currentPlayerIndex];
    return (
      <div className="min-h-screen bg-slate-50 dark:bg-slate-950 text-slate-800 dark:text-slate-100 p-4 transition-colors duration-300">
        <div className="absolute top-4 right-4"><ThemeToggle /></div>
        <div className="max-w-4xl mx-auto">
            <div className="text-center mb-8">
                <h1 className="text-5xl font-black text-emerald-500 mb-2">{isMatchOver ? 'MATCH WINNER!' : 'LEG FINISHED'}</h1>
                <p className="text-2xl text-slate-600 dark:text-slate-400">{winner.name} wins {isMatchOver ? 'the match' : `leg ${state.currentLeg}`}.</p>
                <div className="mt-2 text-lg font-bold text-slate-500">
                    Match Score: {players.map(p => `${p.name}: ${p.wins}`).join(' - ')}
                </div>
                <div className="mt-6 flex justify-center gap-4">
                    {isMatchOver ? (
                        <button onClick={restartMatch} className="bg-emerald-500 hover:bg-emerald-600 text-white shadow-lg shadow-emerald-200 dark:shadow-emerald-900/50 px-8 py-3 rounded-xl font-bold transition-all transform hover:-translate-y-1">Rematch</button>
                    ) : (
                         <button onClick={startNextLeg} className="bg-emerald-500 hover:bg-emerald-600 text-white shadow-lg shadow-emerald-200 dark:shadow-emerald-900/50 px-8 py-3 rounded-xl font-bold transition-all transform hover:-translate-y-1">Start Leg {state.currentLeg + 1}</button>
                    )}
                    <button onClick={handleUndo} className="bg-amber-500 hover:bg-amber-600 text-white shadow-lg shadow-amber-200 dark:shadow-amber-900/50 px-6 py-3 rounded-xl font-bold transition-all transform hover:-translate-y-1">Correction / Undo</button>
                    <button onClick={newGame} className="bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-700 text-slate-700 dark:text-slate-200 hover:bg-slate-50 dark:hover:bg-slate-700 shadow-sm px-6 py-3 rounded-xl font-bold transition-all">New Setup</button>
                </div>
            </div>

            <div className="grid md:grid-cols-2 gap-8">
                {players.map(p => (
                    <div key={p.id} className="bg-white dark:bg-slate-800 p-6 rounded-2xl shadow-sm border border-slate-100 dark:border-slate-700">
                        <div className="flex justify-between items-center mb-4">
                            <div className="flex items-center gap-2">
                                <h3 className="text-xl font-bold text-slate-700 dark:text-slate-300">{p.name}</h3>
                                {p.id === winner.id && <span className="text-emerald-500">👑</span>}
                            </div>
                            <div className="flex flex-col items-end">
                                <span className="text-sm font-bold text-slate-500">Wins: {p.wins}</span>
                                <span className="text-xs font-semibold bg-slate-100 dark:bg-slate-700 px-2 py-1 rounded text-slate-500 dark:text-slate-400 mt-1">
                                    Avg: {Math.round(((config?.startingScore || 501) * state.currentLeg - p.score) / (Math.max(1, state.history.filter(t => t.playerId === p.id).length) / 3) || 0)}
                                </span>
                            </div>
                        </div>
                        <div className="flex justify-center mb-4">
                             <DartboardHeatmap history={state.history} playerId={p.id} isDarkMode={isDarkMode} />
                        </div>
                    </div>
                ))}
            </div>
        </div>
      </div>
    );
  }

  const currentPlayer = players[state.currentPlayerIndex];

  return (
    <div className="min-h-screen bg-slate-50 dark:bg-slate-950 text-slate-800 dark:text-slate-100 p-4 flex flex-col transition-colors duration-300 relative overflow-hidden">

      {/* BULL ANIMATION OVERLAY - FIXED CENTERING */}
      {showBullAnimation && (
        <div className="fixed inset-0 z-50 flex items-center justify-center pointer-events-none">
            <div className="absolute inset-0 bg-white/20 dark:bg-black/20 backdrop-blur-sm animate-fade-in"></div>
            <div className="animate-bull-blast origin-center relative">
                 <div className="bg-red-600 text-white font-black text-6xl md:text-8xl px-12 py-8 rounded-[3rem] shadow-2xl border-8 border-white dark:border-slate-800 transform rotate-3 whitespace-nowrap tracking-tighter">BULL!</div>
            </div>
        </div>
      )}

      {/* DOUBLE BULL ANIMATION OVERLAY - FIXED CENTERING */}
      {showDoubleBullAnimation && (
        <div className="fixed inset-0 z-50 flex items-center justify-center pointer-events-none">
            <div className="absolute inset-0 bg-red-500/10 dark:bg-red-900/10 backdrop-blur-[2px] animate-fade-in"></div>
            <div className="animate-dbull-blast origin-center relative">
                 <div className="bg-gradient-to-br from-amber-400 via-red-600 to-amber-600 text-white font-black text-7xl md:text-9xl px-16 py-10 rounded-[4rem] shadow-[0_0_50px_rgba(251,191,36,0.5)] border-8 border-white dark:border-slate-800 transform whitespace-nowrap tracking-tighter italic animate-gold-pulse">
                    DOUBLE BULL!
                </div>
            </div>
        </div>
      )}

      {showWinAnimation && (
        <div className="fixed inset-0 z-[60] flex items-center justify-center overflow-hidden pointer-events-none">
            <div className="absolute inset-0 bg-emerald-500/90 dark:bg-emerald-900/90 backdrop-blur-md"></div>
            {[...Array(20)].map((_, i) => (
                <div key={i} className="confetti" style={{ left: `${Math.random() * 100}%`, backgroundColor: ['#fbbf24', '#f87171', '#34d399', '#60a5fa'][Math.floor(Math.random() * 4)], animationDelay: `${Math.random() * 2}s`, animationDuration: `${2 + Math.random() * 3}s` }}></div>
            ))}
            <div className="animate-winner-pop text-center relative z-10">
                <h2 className="text-4xl font-bold text-white mb-4 uppercase tracking-widest opacity-80">{isMatchOver ? 'MATCH WINNER' : 'LEG WINNER'}</h2>
                <div className="bg-white text-emerald-600 font-black text-6xl md:text-9xl px-12 py-6 rounded-3xl shadow-2xl transform -rotate-2 whitespace-nowrap tracking-tighter">{players[state.currentPlayerIndex].name}</div>
                <div className="mt-8 text-white text-2xl font-bold animate-pulse">Game Shot!</div>
            </div>
        </div>
      )}

      <header className="flex justify-between items-center mb-4 max-w-md mx-auto w-full relative z-10">
        <h1 className="font-bold text-slate-400 dark:text-slate-500 tracking-wider uppercase text-sm">Leg {state.currentLeg} <span className="text-xs opacity-70"> (First to {targetWins})</span></h1>
        <div className="flex items-center gap-4">
            <ThemeToggle />
            <button onClick={newGame} className="text-xs text-slate-500 dark:text-slate-400 hover:text-slate-700 dark:hover:text-slate-200 font-medium">Quit</button>
        </div>
      </header>

      <main className="flex-1 flex flex-col justify-center relative z-10">
        <Scoreboard players={players} currentPlayerId={currentPlayer.id} currentTurnThrows={state.turnThrows} scoreAtStartOfTurn={state.scoreAtStartOfTurn} history={state.history} />
        <InputPad onSubmitThrow={handleThrow} onUndo={handleUndo} canUndo={state.history.length > 0} />
      </main>
    </div>
  );
};

export default App;

import React from 'react';
import { Player, Throw } from '../types';
import { MAX_THROWS_PER_TURN, getMultiplierLabel } from '../constants';

interface ScoreboardProps {
  players: Player[];
  currentPlayerId: string;
  currentTurnThrows: Throw[];
  scoreAtStartOfTurn: number;
  history: Throw[];
}

const DartIcon = () => (
  <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round" className="opacity-60">
    <path d="m9 15 3-3 7-7"/>
    <path d="M12 12c-1.5 1.5-3 1.5-4.5 0s0-3 1.5-4.5"/>
    <path d="M14 6c1.5-1.5 3-1.5 4.5 0s0 3-1.5 4.5"/>
    <path d="m3 21 3-3"/>
    <path d="m5 16 3 3"/>
  </svg>
);

export const Scoreboard: React.FC<ScoreboardProps> = ({
  players,
  currentPlayerId,
  currentTurnThrows,
  history
}) => {
    // Calculate current turn total
    const currentTurnTotal = currentTurnThrows.reduce((acc, t) => acc + t.totalPoints, 0);

    const getPlayerDartCount = (playerId: string) => {
      // Darts in history + darts currently being thrown in the active turn
      const historyCount = history.filter(t => t.playerId === playerId).length;
      const activeTurnCount = playerId === currentPlayerId ? currentTurnThrows.length : 0;
      return historyCount + activeTurnCount;
    };

  return (
    <div className="w-full max-w-md mx-auto mb-6">
      {/* Active Player Large Display */}
      {players.map((player) => {
        const isActive = player.id === currentPlayerId;
        if (!isActive) return null;

        const liveScore = player.score; 
        const totalDarts = getPlayerDartCount(player.id);

        return (
            <div key={player.id} className="bg-white dark:bg-slate-800 rounded-3xl p-6 shadow-xl shadow-slate-200/50 dark:shadow-black/30 border border-slate-100 dark:border-slate-700 mb-6 relative overflow-hidden transition-colors">
                <div className="absolute top-0 left-0 w-full h-1.5 bg-gradient-to-r from-emerald-400 to-emerald-500"></div>
                <div className="flex justify-between items-start mb-2">
                    <div>
                        <h2 className="text-2xl font-bold text-slate-800 dark:text-slate-100 tracking-tight flex items-center gap-2">
                          {player.name}
                        </h2>
                        <div className="flex items-center gap-3 mt-1">
                            <p className="text-slate-400 dark:text-slate-500 text-xs font-semibold uppercase tracking-wider">{player.wins} wins</p>
                            <div className="flex items-center gap-1 text-slate-500 dark:text-slate-400 text-xs font-bold bg-slate-100 dark:bg-slate-700/50 px-2 py-0.5 rounded-full border border-slate-200/50 dark:border-slate-600/50">
                                <DartIcon />
                                <span>{totalDarts}</span>
                            </div>
                        </div>
                    </div>
                    <div className="text-right">
                        <div key={liveScore} className="animate-score-pop text-7xl font-black text-slate-800 dark:text-white tracking-tighter leading-none">
                            {liveScore}
                        </div>
                    </div>
                </div>

                {/* Turn Indicators */}
                <div className="flex justify-between items-end mt-6 bg-slate-50 dark:bg-slate-900 p-4 rounded-2xl border border-slate-100/80 dark:border-slate-800">
                     <div className="flex gap-2">
                        {[0, 1, 2].map((i) => {
                            const t = currentTurnThrows[i];
                            return (
                                <div key={i} className="flex flex-col items-center gap-1">
                                    <div className={`w-12 h-14 rounded-xl flex items-center justify-center font-bold text-xl border transition-all duration-200 ${
                                        t 
                                        ? 'animate-pop-in border-emerald-200 dark:border-emerald-800 bg-white dark:bg-slate-800 text-emerald-600 dark:text-emerald-400 shadow-sm' 
                                        : 'border-slate-200 dark:border-slate-700 bg-slate-100 dark:bg-slate-800 text-slate-300 dark:text-slate-600'
                                    }`}>
                                        {t ? (t.scoreValue === 0 ? 'X' : `${getMultiplierLabel(t.multiplier)}${t.scoreValue}`) : '-'}
                                    </div>
                                </div>
                            );
                        })}
                    </div>
                    <div className="text-right">
                        <span className="text-slate-400 dark:text-slate-500 text-[10px] uppercase tracking-widest font-bold">Current Turn</span>
                        <div key={currentTurnTotal} className="text-4xl font-bold text-emerald-500 dark:text-emerald-400 leading-none mt-1 animate-score-pop">
                            {currentTurnTotal}
                        </div>
                    </div>
                </div>
            </div>
        );
      })}

      {/* Other Players List (Compact) */}
      <div className="grid grid-cols-2 gap-3">
        {players.map((player) => {
            const isActive = player.id === currentPlayerId;
            if (isActive) return null;
            const totalDarts = getPlayerDartCount(player.id);
            return (
                <div key={player.id} className="bg-white dark:bg-slate-800 px-4 py-3 rounded-xl border border-slate-200 dark:border-slate-700 shadow-sm opacity-60 grayscale-[0.5] scale-95 origin-center transition-all duration-500">
                    <div className="flex justify-between items-center">
                        <div className="flex flex-col min-w-0">
                          <span className="font-medium text-slate-500 dark:text-slate-400 truncate text-sm">{player.name}</span>
                          <div className="flex items-center gap-1 text-[10px] text-slate-400 font-bold">
                            <DartIcon />
                            <span>{totalDarts}</span>
                          </div>
                        </div>
                        <span className="font-bold text-xl text-slate-700 dark:text-slate-200">{player.score}</span>
                    </div>
                </div>
            );
        })}
      </div>
    </div>
  );
};

import React, { useState, useEffect, useCallback } from 'react';
import { GameStatus, GameConfig, GameState, Player, Throw, Multiplier } from './types';
import { MAX_THROWS_PER_TURN } from './constants';
import { Setup } from './components/Setup';
import { Scoreboard } from './components/Scoreboard';
import { InputPad } from './components/InputPad';
import { DartboardHeatmap } from './components/DartboardHeatmap';

const App: React.FC = () => {
  const [isDarkMode, setIsDarkMode] = useState<boolean>(false);
  const [config, setConfig] = useState<GameConfig | null>(null);
  const [state, setState] = useState<GameState>({
    status: GameStatus.Setup,
    currentLeg: 1,
    currentPlayerIndex: 0,
    legStarterIndex: 0,
    turnThrows: [],
    history: [],
    scoreAtStartOfTurn: 0,
  });
  const [players, setPlayers] = useState<Player[]>([]);
  const [winningThrow, setWinningThrow] = useState<Throw | null>(null);
  const [showBullAnimation, setShowBullAnimation] = useState<boolean>(false);
  const [showDoubleBullAnimation, setShowDoubleBullAnimation] = useState<boolean>(false);
  const [showWinAnimation, setShowWinAnimation] = useState<boolean>(false);

  // Handle Dark Mode Toggle
  useEffect(() => {
    if (isDarkMode) {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  }, [isDarkMode]);

  const toggleTheme = () => setIsDarkMode(!isDarkMode);

  // --- AUDIO UTILS ---
  const playBustSound = () => {
    try {
      const AudioContext = window.AudioContext || (window as any).webkitAudioContext;
      if (!AudioContext) return;
      const ctx = new AudioContext();
      const osc1 = ctx.createOscillator();
      const osc2 = ctx.createOscillator();
      const gain = ctx.createGain();
      osc1.type = 'sawtooth';
      osc2.type = 'square';
      osc1.frequency.setValueAtTime(120, ctx.currentTime);
      osc2.frequency.setValueAtTime(126, ctx.currentTime);
      gain.gain.setValueAtTime(0.2, ctx.currentTime);
      gain.gain.setValueAtTime(0.2, ctx.currentTime + 0.4);
      gain.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + 0.5);
      osc1.connect(gain);
      osc2.connect(gain);
      gain.connect(ctx.destination);
      osc1.start();
      osc2.start();
      const duration = 0.5;
      osc1.stop(ctx.currentTime + duration);
      osc2.stop(ctx.currentTime + duration);
    } catch (e) { console.error("Audio failed", e); }
  };

  const playWinSound = () => {
    try {
      const AudioContext = window.AudioContext || (window as any).webkitAudioContext;
      if (!AudioContext) return;
      const ctx = new AudioContext();
      const gain = ctx.createGain();
      gain.connect(ctx.destination);
      gain.gain.setValueAtTime(0.1, ctx.currentTime);

      const playNote = (freq: number, start: number, duration: number) => {
        const osc = ctx.createOscillator();
        osc.type = 'sine';
        osc.frequency.setValueAtTime(freq, ctx.currentTime + start);
        const noteGain = ctx.createGain();
        noteGain.gain.setValueAtTime(0, ctx.currentTime + start);
        noteGain.gain.linearRampToValueAtTime(0.2, ctx.currentTime + start + 0.05);
        noteGain.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + start + duration);
        osc.connect(noteGain);
        noteGain.connect(gain);
        osc.start(ctx.currentTime + start);
        osc.stop(ctx.currentTime + start + duration);
      };

      const now = 0;
      playNote(523.25, now, 0.4); 
      playNote(659.25, now + 0.15, 0.4); 
      playNote(783.99, now + 0.3, 0.4); 
      playNote(1046.50, now + 0.45, 1.2); 
    } catch (e) { console.error("Audio failed", e); }
  };

  const startGame = (newConfig: GameConfig) => {
    setConfig(newConfig);
    setPlayers(newConfig.players);
    setState({
      status: GameStatus.Playing,
      currentLeg: 1,
      currentPlayerIndex: 0,
      legStarterIndex: 0,
      turnThrows: [],
      history: [],
      scoreAtStartOfTurn: newConfig.players[0].score,
    });
    setWinningThrow(null);
    setShowWinAnimation(false);
  };

  const handleTurnEnd = useCallback((playersSnapshot?: Player[]) => {
    if (!config) return;
    const currentPlayers = playersSnapshot || players;
    setState((prev) => {
        const nextPlayerIndex = (prev.currentPlayerIndex + 1) % currentPlayers.length;
        const nextPlayer = currentPlayers[nextPlayerIndex];
        return {
            ...prev,
            turnThrows: [],
            currentPlayerIndex: nextPlayerIndex,
            scoreAtStartOfTurn: nextPlayer.score,
        };
    });
  }, [config, players]);

  const handleThrow = (value: number, multiplier: Multiplier) => {
    if (state.status !== GameStatus.Playing || !config || showWinAnimation) return;

    if (value === 25) {
      if (multiplier === Multiplier.Double) {
        setShowDoubleBullAnimation(true);
        setTimeout(() => setShowDoubleBullAnimation(false), 1500);
      } else {
        setShowBullAnimation(true);
        setTimeout(() => setShowBullAnimation(false), 1200);
      }
    }

    const currentPlayer = players[state.currentPlayerIndex];
    const points = value * multiplier;
    const newScore = currentPlayer.score - points;
    const now = Date.now();

    let isBust = false;
    let isWin = false;

    if (newScore < 0) {
      isBust = true;
    } else if (newScore === 0) {
      isWin = true;
    }

    const newThrow: Throw = {
      playerId: currentPlayer.id,
      legId: state.currentLeg,
      scoreValue: value,
      multiplier,
      totalPoints: points,
      isBust,
      isWin,
      timestamp: now,
    };

    const updatedPlayers = [...players];
    if (isBust) {
      updatedPlayers[state.currentPlayerIndex].score = state.scoreAtStartOfTurn;
      playBustSound();
    } else {
      updatedPlayers[state.currentPlayerIndex].score = newScore;
    }
    setPlayers(updatedPlayers);

    setState((prev) => {
      const newTurnThrows = [...prev.turnThrows, newThrow];
      const newHistory = [...prev.history, newThrow];
      return {
        ...prev,
        turnThrows: newTurnThrows,
        history: newHistory,
      };
    });

    if (isWin) {
      setWinningThrow(newThrow);
      const winnerUpdate = [...updatedPlayers];
      winnerUpdate[state.currentPlayerIndex].wins += 1;
      setPlayers(winnerUpdate);
      setShowWinAnimation(true);
      playWinSound(); 

      setTimeout(() => {
        setState((prev) => ({ ...prev, status: GameStatus.Summary }));
        setShowWinAnimation(false);
      }, 2500);
      return;
    }

    if (isBust) {
      setTimeout(() => handleTurnEnd(updatedPlayers), 800); 
      return;
    }

    if (state.turnThrows.length + 1 >= MAX_THROWS_PER_TURN) {
      setTimeout(() => handleTurnEnd(updatedPlayers), 500);
    }
  };

  const handleUndo = () => {
    if (state.history.length === 0 || !config) return;

    const newHistory = [...state.history];
    const undoneThrow = newHistory.pop();
    if (!undoneThrow) return;

    const playerIndex = players.findIndex(p => p.id === undoneThrow.playerId);
    if (playerIndex === -1) return;

    const updatedPlayers = players.map(player => {
        const playerLegThrows = newHistory.filter(t => t.playerId === player.id && t.legId === state.currentLeg);

        let currentScore = config.startingScore;
        let scoreAtTurnStart = config.startingScore;
        let turnDartCount = 0;

        for (const t of playerLegThrows) {
            if (turnDartCount === 0) scoreAtTurnStart = currentScore;

            if (t.isBust) {
                currentScore = scoreAtTurnStart;
                turnDartCount = 0;
            } else {
                currentScore -= t.totalPoints;
                turnDartCount++;
                if (turnDartCount >= MAX_THROWS_PER_TURN) turnDartCount = 0;
            }
        }

        return { 
          ...player, 
          score: currentScore, 
          wins: (player.id === undoneThrow.playerId && undoneThrow.isWin) ? player.wins - 1 : player.wins 
        };
    });

    setPlayers(updatedPlayers);

    const playerNewHistory = newHistory.filter(t => t.playerId === undoneThrow.playerId && t.legId === state.currentLeg);

    const lastTurnThrows: Throw[] = [];
    let turnCount = 0;
    for (const t of playerNewHistory) {
        lastTurnThrows.push(t);
        turnCount++;
        if (turnCount >= MAX_THROWS_PER_TURN || t.isBust) {
            lastTurnThrows.length = 0;
            turnCount = 0;
        }
    }

    const pointsInCurrentUnfinishedTurn = lastTurnThrows.reduce((sum, t) => sum + t.totalPoints, 0);
    const scoreAtStartOfTurn = updatedPlayers[playerIndex].score + pointsInCurrentUnfinishedTurn;

    setState((prev) => ({
        ...prev,
        status: GameStatus.Playing,
        currentPlayerIndex: playerIndex,
        turnThrows: lastTurnThrows,
        history: newHistory,
        scoreAtStartOfTurn: scoreAtStartOfTurn,
    }));

    setWinningThrow(null);
  };

  const targetWins = config ? Math.ceil(config.totalLegs / 2) : 1;
  const isMatchOver = players.some(p => p.wins >= targetWins);

  const startNextLeg = () => {
    if (!config) return;
    const nextLegPlayers = players.map(p => ({ ...p, score: config.startingScore }));
    setPlayers(nextLegPlayers);
    const nextStarterIndex = (state.legStarterIndex + 1) % players.length;
    setState(prev => ({
        ...prev,
        status: GameStatus.Playing,
        currentLeg: prev.currentLeg + 1,
        currentPlayerIndex: nextStarterIndex,
        legStarterIndex: nextStarterIndex,
        turnThrows: [],
        scoreAtStartOfTurn: config.startingScore,
    }));
    setWinningThrow(null);
    setShowWinAnimation(false);
  };

  const restartMatch = () => {
    if (!config) return;
    const resetPlayers = players.map(p => ({ ...p, score: config.startingScore, wins: 0 }));
    const matchConfig = { ...config, players: resetPlayers };
    startGame(matchConfig);
  };

  const newGame = () => setState((prev) => ({ ...prev, status: GameStatus.Setup }));

  const ThemeToggle = () => (
    <button 
        onClick={toggleTheme}
        className="p-2 rounded-full bg-slate-200 dark:bg-slate-800 text-slate-600 dark:text-slate-300 hover:bg-slate-300 dark:hover:bg-slate-700 transition-colors"
        title="Toggle Theme"
    >
        {isDarkMode ? '🌙' : '☀️'}
    </button>
  );

  if (state.status === GameStatus.Setup) {
    return (
        <div className="min-h-screen bg-slate-50 dark:bg-slate-950 text-slate-800 dark:text-slate-100 p-4 flex flex-col items-center justify-center transition-colors duration-300">
            <div className="absolute top-4 right-4"><ThemeToggle /></div>
            <Setup onStartGame={startGame} />
        </div>
    );
  }

  if (state.status === GameStatus.Summary) {
    const winner = players[state.currentPlayerIndex];
    return (
      <div className="min-h-screen bg-slate-50 dark:bg-slate-950 text-slate-800 dark:text-slate-100 p-4 transition-colors duration-300">
        <div className="absolute top-4 right-4"><ThemeToggle /></div>
        <div className="max-w-4xl mx-auto">
            <div className="text-center mb-8">
                <h1 className="text-5xl font-black text-emerald-500 mb-2">{isMatchOver ? 'MATCH WINNER!' : 'LEG FINISHED'}</h1>
                <p className="text-2xl text-slate-600 dark:text-slate-400">{winner.name} wins {isMatchOver ? 'the match' : `leg ${state.currentLeg}`}.</p>
                <div className="mt-2 text-lg font-bold text-slate-500">
                    Match Score: {players.map(p => `${p.name}: ${p.wins}`).join(' - ')}
                </div>
                <div className="mt-6 flex justify-center gap-4">
                    {isMatchOver ? (
                        <button onClick={restartMatch} className="bg-emerald-500 hover:bg-emerald-600 text-white shadow-lg shadow-emerald-200 dark:shadow-emerald-900/50 px-8 py-3 rounded-xl font-bold transition-all transform hover:-translate-y-1">Rematch</button>
                    ) : (
                         <button onClick={startNextLeg} className="bg-emerald-500 hover:bg-emerald-600 text-white shadow-lg shadow-emerald-200 dark:shadow-emerald-900/50 px-8 py-3 rounded-xl font-bold transition-all transform hover:-translate-y-1">Start Leg {state.currentLeg + 1}</button>
                    )}
                    <button onClick={handleUndo} className="bg-amber-500 hover:bg-amber-600 text-white shadow-lg shadow-amber-200 dark:shadow-amber-900/50 px-6 py-3 rounded-xl font-bold transition-all transform hover:-translate-y-1">Correction / Undo</button>
                    <button onClick={newGame} className="bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-700 text-slate-700 dark:text-slate-200 hover:bg-slate-50 dark:hover:bg-slate-700 shadow-sm px-6 py-3 rounded-xl font-bold transition-all">New Setup</button>
                </div>
            </div>

            <div className="grid md:grid-cols-2 gap-8">
                {players.map(p => (
                    <div key={p.id} className="bg-white dark:bg-slate-800 p-6 rounded-2xl shadow-sm border border-slate-100 dark:border-slate-700">
                        <div className="flex justify-between items-center mb-4">
                            <div className="flex items-center gap-2">
                                <h3 className="text-xl font-bold text-slate-700 dark:text-slate-300">{p.name}</h3>
                                {p.id === winner.id && <span className="text-emerald-500">👑</span>}
                            </div>
                            <div className="flex flex-col items-end">
                                <span className="text-sm font-bold text-slate-500">Wins: {p.wins}</span>
                                <span className="text-xs font-semibold bg-slate-100 dark:bg-slate-700 px-2 py-1 rounded text-slate-500 dark:text-slate-400 mt-1">
                                    Avg: {Math.round(((config?.startingScore || 501) * state.currentLeg - p.score) / (Math.max(1, state.history.filter(t => t.playerId === p.id).length) / 3) || 0)}
                                </span>
                            </div>
                        </div>
                        <div className="flex justify-center mb-4">
                             <DartboardHeatmap history={state.history} playerId={p.id} isDarkMode={isDarkMode} />
                        </div>
                    </div>
                ))}
            </div>
        </div>
      </div>
    );
  }

  const currentPlayer = players[state.currentPlayerIndex];

  return (
    <div className="min-h-screen bg-slate-50 dark:bg-slate-950 text-slate-800 dark:text-slate-100 p-4 flex flex-col transition-colors duration-300 relative overflow-hidden">

      {/* BULL ANIMATION OVERLAY - FIXED CENTERING */}
      {showBullAnimation && (
        <div className="fixed inset-0 z-50 flex items-center justify-center pointer-events-none">
            <div className="absolute inset-0 bg-white/20 dark:bg-black/20 backdrop-blur-sm animate-fade-in"></div>
            <div className="animate-bull-blast origin-center relative">
                 <div className="bg-red-600 text-white font-black text-6xl md:text-8xl px-12 py-8 rounded-[3rem] shadow-2xl border-8 border-white dark:border-slate-800 transform rotate-3 whitespace-nowrap tracking-tighter">BULL!</div>
            </div>
        </div>
      )}

      {/* DOUBLE BULL ANIMATION OVERLAY - FIXED CENTERING */}
      {showDoubleBullAnimation && (
        <div className="fixed inset-0 z-50 flex items-center justify-center pointer-events-none">
            <div className="absolute inset-0 bg-red-500/10 dark:bg-red-900/10 backdrop-blur-[2px] animate-fade-in"></div>
            <div className="animate-dbull-blast origin-center relative">
                 <div className="bg-gradient-to-br from-amber-400 via-red-600 to-amber-600 text-white font-black text-7xl md:text-9xl px-16 py-10 rounded-[4rem] shadow-[0_0_50px_rgba(251,191,36,0.5)] border-8 border-white dark:border-slate-800 transform whitespace-nowrap tracking-tighter italic animate-gold-pulse">
                    DOUBLE BULL!
                </div>
            </div>
        </div>
      )}

      {showWinAnimation && (
        <div className="fixed inset-0 z-[60] flex items-center justify-center overflow-hidden pointer-events-none">
            <div className="absolute inset-0 bg-emerald-500/90 dark:bg-emerald-900/90 backdrop-blur-md"></div>
            {[...Array(20)].map((_, i) => (
                <div key={i} className="confetti" style={{ left: `${Math.random() * 100}%`, backgroundColor: ['#fbbf24', '#f87171', '#34d399', '#60a5fa'][Math.floor(Math.random() * 4)], animationDelay: `${Math.random() * 2}s`, animationDuration: `${2 + Math.random() * 3}s` }}></div>
            ))}
            <div className="animate-winner-pop text-center relative z-10">
                <h2 className="text-4xl font-bold text-white mb-4 uppercase tracking-widest opacity-80">{isMatchOver ? 'MATCH WINNER' : 'LEG WINNER'}</h2>
                <div className="bg-white text-emerald-600 font-black text-6xl md:text-9xl px-12 py-6 rounded-3xl shadow-2xl transform -rotate-2 whitespace-nowrap tracking-tighter">{players[state.currentPlayerIndex].name}</div>
                <div className="mt-8 text-white text-2xl font-bold animate-pulse">Game Shot!</div>
            </div>
        </div>
      )}

      <header className="flex justify-between items-center mb-4 max-w-md mx-auto w-full relative z-10">
        <h1 className="font-bold text-slate-400 dark:text-slate-500 tracking-wider uppercase text-sm">Leg {state.currentLeg} <span className="text-xs opacity-70"> (First to {targetWins})</span></h1>
        <div className="flex items-center gap-4">
            <ThemeToggle />
            <button onClick={newGame} className="text-xs text-slate-500 dark:text-slate-400 hover:text-slate-700 dark:hover:text-slate-200 font-medium">Quit</button>
        </div>
      </header>

      <main className="flex-1 flex flex-col justify-center relative z-10">
        <Scoreboard 
          players={players} 
          currentPlayerId={currentPlayer.id} 
          currentTurnThrows={state.turnThrows} 
          scoreAtStartOfTurn={state.scoreAtStartOfTurn} 
          history={state.history} 
        />
        <InputPad onSubmitThrow={handleThrow} onUndo={handleUndo} canUndo={state.history.length > 0} />
      </main>
    </div>
  );
};

export default App;

export enum Multiplier {
  Single = 1,
  Double = 2,
  Triple = 3,
}

export interface Throw {
  playerId: string;
  legId: number;
  scoreValue: number;
  multiplier: Multiplier;
  totalPoints: number;
  isBust: boolean;
  isWin: boolean;
  timestamp: number;
}

export interface Player {
  id: string;
  name: string;
  score: number;
  wins: number;
}

export enum GameStatus {
  Setup,
  Playing,
  Summary,
}

export interface GameConfig {
  startingScore: number;
  totalLegs: number;
  players: Player[];
}

export interface GameState {
  status: GameStatus;
  currentLeg: number;
  currentPlayerIndex: number;
  legStarterIndex: number;
  turnThrows: Throw[];
  history: Throw[];
  scoreAtStartOfTurn: number;
  finishedPlayerIds: string[]; // Order of finishing
}

import React, { useState, useEffect, useCallback } from 'react';
import { GameStatus, GameConfig, GameState, Player, Throw, Multiplier } from './types';
import { MAX_THROWS_PER_TURN } from './constants';
import { Setup } from './components/Setup';
import { Scoreboard } from './components/Scoreboard';
import { InputPad } from './components/InputPad';
import { DartboardHeatmap } from './components/DartboardHeatmap';

const App: React.FC = () => {
  const [isDarkMode, setIsDarkMode] = useState<boolean>(false);
  const [config, setConfig] = useState<GameConfig | null>(null);
  const [state, setState] = useState<GameState>({
    status: GameStatus.Setup,
    currentLeg: 1,
    currentPlayerIndex: 0,
    legStarterIndex: 0,
    turnThrows: [],
    history: [],
    scoreAtStartOfTurn: 0,
    finishedPlayerIds: [],
  });
  const [players, setPlayers] = useState<Player[]>([]);
  const [showBullAnimation, setShowBullAnimation] = useState<boolean>(false);
  const [showDoubleBullAnimation, setShowDoubleBullAnimation] = useState<boolean>(false);
  const [showWinAnimation, setShowWinAnimation] = useState<boolean>(false);

  useEffect(() => {
    if (isDarkMode) document.documentElement.classList.add('dark');
    else document.documentElement.classList.remove('dark');
  }, [isDarkMode]);

  const toggleTheme = () => setIsDarkMode(!isDarkMode);

  const playBustSound = () => {
    try {
      const AudioContext = window.AudioContext || (window as any).webkitAudioContext;
      const ctx = new AudioContext();
      const osc1 = ctx.createOscillator();
      const osc2 = ctx.createOscillator();
      const gain = ctx.createGain();
      osc1.type = 'sawtooth'; osc2.type = 'square';
      osc1.frequency.setValueAtTime(120, ctx.currentTime);
      osc2.frequency.setValueAtTime(126, ctx.currentTime);
      gain.gain.setValueAtTime(0.2, ctx.currentTime);
      gain.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + 0.5);
      osc1.connect(gain); osc2.connect(gain); gain.connect(ctx.destination);
      osc1.start(); osc2.start();
      osc1.stop(ctx.currentTime + 0.5); osc2.stop(ctx.currentTime + 0.5);
    } catch (e) {}
  };

  const playWinSound = () => {
    try {
      const AudioContext = window.AudioContext || (window as any).webkitAudioContext;
      const ctx = new AudioContext();
      const gain = ctx.createGain();
      gain.connect(ctx.destination);
      gain.gain.setValueAtTime(0.1, ctx.currentTime);
      const playNote = (freq: number, start: number, duration: number) => {
        const osc = ctx.createOscillator();
        osc.type = 'sine';
        osc.frequency.setValueAtTime(freq, ctx.currentTime + start);
        const noteGain = ctx.createGain();
        noteGain.gain.setValueAtTime(0, ctx.currentTime + start);
        noteGain.gain.linearRampToValueAtTime(0.2, ctx.currentTime + start + 0.05);
        noteGain.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + start + duration);
        osc.connect(noteGain); noteGain.connect(gain);
        osc.start(ctx.currentTime + start); osc.stop(ctx.currentTime + start + duration);
      };
      playNote(523.25, 0, 0.4); playNote(659.25, 0.15, 0.4); playNote(783.99, 0.3, 0.4); playNote(1046.50, 0.45, 1.2);
    } catch (e) {}
  };

  const startGame = (newConfig: GameConfig) => {
    setConfig(newConfig);
    setPlayers(newConfig.players);
    setState({
      status: GameStatus.Playing,
      currentLeg: 1,
      currentPlayerIndex: 0,
      legStarterIndex: 0,
      turnThrows: [],
      history: [],
      scoreAtStartOfTurn: newConfig.players[0].score,
      finishedPlayerIds: [],
    });
    setShowWinAnimation(false);
  };

  const getNextPlayerIndex = (currentIndex: number, allPlayers: Player[], finished: string[]) => {
    let next = (currentIndex + 1) % allPlayers.length;
    // Keep skipping if the player is already finished
    while (finished.includes(allPlayers[next].id)) {
      next = (next + 1) % allPlayers.length;
      if (next === currentIndex) break;
    }
    return next;
  };

  const handleTurnEnd = useCallback((playersSnapshot?: Player[], finishedSnapshot?: string[]) => {
    if (!config) return;
    const currentPlayers = playersSnapshot || players;
    const finished = finishedSnapshot || state.finishedPlayerIds;

    setState((prev) => {
        const nextIdx = getNextPlayerIndex(prev.currentPlayerIndex, currentPlayers, finished);
        return {
            ...prev,
            turnThrows: [],
            currentPlayerIndex: nextIdx,
            scoreAtStartOfTurn: currentPlayers[nextIdx].score,
        };
    });
  }, [config, players, state.finishedPlayerIds]);

  const handleThrow = (value: number, multiplier: Multiplier) => {
    if (state.status !== GameStatus.Playing || !config || showWinAnimation) return;

    if (value === 25) {
      if (multiplier === Multiplier.Double) { setShowDoubleBullAnimation(true); setTimeout(() => setShowDoubleBullAnimation(false), 1500); }
      else { setShowBullAnimation(true); setTimeout(() => setShowBullAnimation(false), 1200); }
    }

    const currentPlayer = players[state.currentPlayerIndex];
    const points = value * multiplier;
    const newScore = currentPlayer.score - points;
    const now = Date.now();

    let isBust = newScore < 0;
    let isWin = newScore === 0;

    const newThrow: Throw = {
      playerId: currentPlayer.id,
      legId: state.currentLeg,
      scoreValue: value,
      multiplier,
      totalPoints: points,
      isBust,
      isWin,
      timestamp: now,
    };

    const updatedPlayers = [...players];
    if (isBust) {
      updatedPlayers[state.currentPlayerIndex].score = state.scoreAtStartOfTurn;
      playBustSound();
    } else {
      updatedPlayers[state.currentPlayerIndex].score = newScore;
    }
    setPlayers(updatedPlayers);

    let newFinished = [...state.finishedPlayerIds];
    if (isWin) {
        newFinished.push(currentPlayer.id);
        playWinSound();
        setShowWinAnimation(true);
        setTimeout(() => setShowWinAnimation(false), 2000);
    }

    setState((prev) => ({
        ...prev,
        turnThrows: [...prev.turnThrows, newThrow],
        history: [...prev.history, newThrow],
        finishedPlayerIds: newFinished,
    }));

    // If only 1 player remains, game is over
    if (newFinished.length >= players.length - 1) {
        // Automatically add the last remaining player to the ranking
        const lastPlayer = players.find(p => !newFinished.includes(p.id));
        if (lastPlayer && !newFinished.includes(lastPlayer.id)) {
            newFinished.push(lastPlayer.id);
        }
        setTimeout(() => setState(prev => ({ ...prev, status: GameStatus.Summary, finishedPlayerIds: newFinished })), 2500);
        return;
    }

    if (isBust || isWin || state.turnThrows.length + 1 >= MAX_THROWS_PER_TURN) {
      setTimeout(() => handleTurnEnd(updatedPlayers, newFinished), isBust || isWin ? 800 : 500);
    }
  };

  const handleUndo = () => {
    if (state.history.length === 0 || !config) return;
    const newHistory = [...state.history];
    const undoneThrow = newHistory.pop()!;

    // Recalculate everything from history to avoid cumulative errors
    const updatedPlayers = players.map(player => {
        const pHistory = newHistory.filter(t => t.playerId === player.id && t.legId === state.currentLeg);
        let curScore = config.startingScore;
        let turnStart = config.startingScore;
        let dartCount = 0;
        for (const t of pHistory) {
            if (dartCount === 0) turnStart = curScore;
            if (t.isBust) { curScore = turnStart; dartCount = 0; }
            else { curScore -= t.totalPoints; dartCount++; if (dartCount >= 3) dartCount = 0; }
        }
        return { ...player, score: curScore };
    });
    setPlayers(updatedPlayers);

    const newFinished = state.finishedPlayerIds.filter(id => {
        // Remove from finished if the undone throw was their winning throw
        if (id === undoneThrow.playerId && undoneThrow.isWin) return false;
        return true;
    });

    const pIndex = players.findIndex(p => p.id === undoneThrow.playerId);
    const pNewHist = newHistory.filter(t => t.playerId === undoneThrow.playerId && t.legId === state.currentLeg);
    const lastTurnThrows: Throw[] = [];
    let turnCount = 0;
    for (const t of pNewHist) {
        lastTurnThrows.push(t); turnCount++;
        if (turnCount >= 3 || t.isBust) { lastTurnThrows.length = 0; turnCount = 0; }
    }
    const unfinishedPoints = lastTurnThrows.reduce((s, t) => s + t.totalPoints, 0);

    setState(prev => ({
        ...prev,
        status: GameStatus.Playing,
        currentPlayerIndex: pIndex,
        turnThrows: lastTurnThrows,
        history: newHistory,
        scoreAtStartOfTurn: updatedPlayers[pIndex].score + unfinishedPoints,
        finishedPlayerIds: newFinished,
    }));
  };

  const startNextLeg = () => {
    if (!config) return;
    setPlayers(players.map(p => ({ ...p, score: config.startingScore })));
    const nextStart = (state.legStarterIndex + 1) % players.length;
    setState(prev => ({
        ...prev,
        status: GameStatus.Playing,
        currentLeg: prev.currentLeg + 1,
        currentPlayerIndex: nextStart,
        legStarterIndex: nextStart,
        turnThrows: [],
        scoreAtStartOfTurn: config.startingScore,
        finishedPlayerIds: [],
    }));
  };

  const restartMatch = () => startGame({ ...config!, players: players.map(p => ({ ...p, score: config!.startingScore, wins: 0 })) });
  const newGame = () => setState(prev => ({ ...prev, status: GameStatus.Setup }));

  const ThemeToggle = () => (
    <button onClick={toggleTheme} className="p-2 rounded-full bg-slate-200 dark:bg-slate-800 text-slate-600 dark:text-slate-300 transition-colors">
        {isDarkMode ? '🌙' : '☀️'}
    </button>
  );

  if (state.status === GameStatus.Setup) return (
    <div className="min-h-screen bg-slate-50 dark:bg-slate-950 flex flex-col items-center justify-center p-4">
        <div className="absolute top-4 right-4"><ThemeToggle /></div>
        <Setup onStartGame={startGame} />
    </div>
  );

  if (state.status === GameStatus.Summary) {
    return (
      <div className="min-h-screen bg-slate-50 dark:bg-slate-950 p-4">
        <div className="absolute top-4 right-4"><ThemeToggle /></div>
        <div className="max-w-4xl mx-auto">
            <h1 className="text-4xl font-black text-center text-emerald-500 mb-8">CLASSEMENT FINAL</h1>
            <div className="grid gap-4 mb-8">
                {state.finishedPlayerIds.map((id, index) => {
                    const p = players.find(player => player.id === id)!;
                    const darts = state.history.filter(t => t.playerId === id).length;
                    return (
                        <div key={id} className={`flex items-center gap-4 p-6 rounded-2xl bg-white dark:bg-slate-800 shadow-lg border-l-8 ${index === 0 ? 'border-emerald-500' : 'border-slate-300'}`}>
                            <div className="text-3xl font-black text-slate-400 w-12">{index + 1}e</div>
                            <div className="flex-1">
                                <div className="text-xl font-bold">{p.name}</div>
                                <div className="text-xs text-slate-500 font-bold uppercase">{darts} fléchettes • Moy: {Math.round((config!.startingScore / (darts/3)))}</div>
                            </div>
                            {index === 0 && <div className="text-3xl">🏆</div>}
                            <div className="w-32 h-32 hidden md:block">
                                <DartboardHeatmap history={state.history} playerId={id} isDarkMode={isDarkMode} />
                            </div>
                        </div>
                    );
                })}
            </div>
            <div className="flex justify-center gap-4">
                <button onClick={restartMatch} className="bg-emerald-500 text-white px-8 py-3 rounded-xl font-bold shadow-lg">Rejouer</button>
                <button onClick={newGame} className="bg-white dark:bg-slate-700 text-slate-700 dark:text-white px-8 py-3 rounded-xl font-bold border border-slate-200 dark:border-slate-600">Nouveau setup</button>
            </div>
        </div>
      </div>
    );
  }

  const currentPlayer = players[state.currentPlayerIndex];

  return (
    <div className="min-h-screen bg-slate-50 dark:bg-slate-950 p-4 flex flex-col transition-colors relative overflow-hidden">
      {showBullAnimation && <div className="fixed inset-0 z-50 flex items-center justify-center pointer-events-none"><div className="animate-bull-blast bg-red-600 text-white font-black text-7xl px-12 py-8 rounded-[3rem] shadow-2xl">BULL!</div></div>}
      {showDoubleBullAnimation && <div className="fixed inset-0 z-50 flex items-center justify-center pointer-events-none"><div className="animate-dbull-blast bg-amber-500 text-white font-black text-7xl px-12 py-8 rounded-[3rem] shadow-2xl animate-gold-pulse">D-BULL!</div></div>}

      {showWinAnimation && (
        <div className="fixed inset-0 z-[60] flex items-center justify-center pointer-events-none">
            <div className="absolute inset-0 bg-emerald-500/80 backdrop-blur-md"></div>
            <div className="animate-winner-pop text-center">
                <h2 className="text-2xl text-white font-bold mb-2 uppercase tracking-widest">Joueur qualifié !</h2>
                <div className="bg-white text-emerald-600 font-black text-6xl px-12 py-6 rounded-3xl shadow-2xl">{currentPlayer.name}</div>
                <div className="mt-4 text-white text-4xl font-black"># {state.finishedPlayerIds.length}</div>
            </div>
        </div>
      )}

      <header className="flex justify-between items-center mb-4 max-w-md mx-auto w-full">
        <h1 className="font-bold text-slate-400 uppercase text-xs">Leg {state.currentLeg}</h1>
        <div className="flex items-center gap-4">
            <ThemeToggle />
            <button onClick={newGame} className="text-xs text-slate-500 font-bold">Quitter</button>
        </div>
      </header>

      <main className="flex-1 flex flex-col justify-center">
        <Scoreboard 
          players={players} 
          currentPlayerId={currentPlayer.id} 
          currentTurnThrows={state.turnThrows} 
          scoreAtStartOfTurn={state.scoreAtStartOfTurn} 
          history={state.history}
          finishedPlayerIds={state.finishedPlayerIds}
        />
        <InputPad onSubmitThrow={handleThrow} onUndo={handleUndo} canUndo={state.history.length > 0} />
      </main>
    </div>
  );
};

