import React from 'react';
import { Player, Throw } from '../types';
import { getMultiplierLabel } from '../constants';

interface ScoreboardProps {
  players: Player[];
  currentPlayerId: string;
  currentTurnThrows: Throw[];
  scoreAtStartOfTurn: number;
  history: Throw[];
  finishedPlayerIds: string[];
}

const DartIcon = () => (
  <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round" className="opacity-60">
    <path d="m9 15 3-3 7-7"/><path d="M12 12c-1.5 1.5-3 1.5-4.5 0s0-3 1.5-4.5"/><path d="M14 6c1.5-1.5 3-1.5 4.5 0s0 3-1.5 4.5"/><path d="m3 21 3-3"/><path d="m5 16 3 3"/>
