    const getPlayerDartCount = (playerId: string) => {
      const historyCount = history.filter(t => t.playerId === playerId).length;
      const activeTurnCount = playerId === currentPlayerId ? currentTurnThrows.length : 0;
      return historyCount + activeTurnCount;
    };

    const getRank = (playerId: string) => {
        const idx = finishedPlayerIds.indexOf(playerId);
