                <div className="flex justify-between items-start mb-2">
                    <div>
                        <h2 className="text-2xl font-bold text-slate-800 dark:text-slate-100 tracking-tight">{player.name}</h2>
                        <div className="flex items-center gap-3 mt-1">
                            <div className="flex items-center gap-1 text-slate-500 dark:text-slate-400 text-xs font-bold bg-slate-100 dark:bg-slate-700/50 px-2 py-0.5 rounded-full">
                                <DartIcon />
                                <span>{getPlayerDartCount(player.id)}</span>
                            </div>
                        </div>
                    </div>
                    <div className="text-right">
                        <div key={player.score} className="animate-score-pop text-7xl font-black text-slate-800 dark:text-white tracking-tighter leading-none">
                            {player.score}
                        </div>
                    </div>
                </div>

                <div className="flex justify-between items-end mt-6 bg-slate-50 dark:bg-slate-900 p-4 rounded-2xl border border-slate-100/80 dark:border-slate-800">
                     <div className="flex gap-2">
                        {[0, 1, 2].map((i) => {
                            const t = currentTurnThrows[i];
                            return (
                                <div key={i} className={`w-12 h-14 rounded-xl flex items-center justify-center font-bold text-xl border transition-all ${
                                    t ? 'animate-pop-in border-emerald-200 bg-white dark:bg-slate-800 text-emerald-600' : 'border-slate-200 dark:border-slate-700 bg-slate-100 dark:bg-slate-800 text-slate-300'
                                }`}>
                                    {t ? (t.scoreValue === 0 ? 'X' : `${getMultiplierLabel(t.multiplier)}${t.scoreValue}`) : '-'}
                                </div>
