                        })}
                    </div>
                    <div className="text-right">
                        <span className="text-slate-400 text-[10px] uppercase tracking-widest font-bold">Tour</span>
                        <div className="text-4xl font-bold text-emerald-500 leading-none mt-1">{currentTurnTotal}</div>
                    </div>
                </div>
            </div>
        );
      })}

      {/* Others & Finished */}
      <div className="grid grid-cols-2 gap-3">
        {players.map((player) => {
            if (player.id === currentPlayerId && !finishedPlayerIds.includes(player.id)) return null;
            const rank = getRank(player.id);
            const isFinished = rank !== null;

            return (
                <div key={player.id} className={`bg-white dark:bg-slate-800 px-4 py-3 rounded-xl border shadow-sm transition-all ${isFinished ? 'border-emerald-500/30' : 'border-slate-200 dark:border-slate-700 opacity-60 grayscale'}`}>
