import React from 'react';
import { Throw, Multiplier } from '../types';
import { DARTBOARD_NUMBERS, getMultiplierLabel } from '../constants';

interface PrecisionAnalysisProps {
  history: Throw[];
  playerId: string;
}

export const PrecisionAnalysis: React.FC<PrecisionAnalysisProps> = ({ history, playerId }) => {
  const playerThrows = history.filter(t => t.playerId === playerId);
  if (playerThrows.length === 0) return null;

  // 1. Group by unique segment (Target Detection)
  const counts: Record<string, number> = {};
  playerThrows.forEach(t => {
    const key = `${getMultiplierLabel(t.multiplier)}${t.scoreValue === 25 ? (t.multiplier === 2 ? 'D-Bull' : 'Bull') : t.scoreValue}`;
    counts[key] = (counts[key] || 0) + 1;
  });

  const sortedSegments = Object.entries(counts).sort((a, b) => b[1] - a[1]);
  const primaryZoneKey = sortedSegments[0][0];
  const primaryCount = sortedSegments[0][1];

  let secondaryZoneKey: string | null = null;
  if (sortedSegments.length > 1) {
    const [key, count] = sortedSegments[1];
    if (count >= primaryCount * 0.25) {
      secondaryZoneKey = key;
    }
  }

  const targetKeys = [primaryZoneKey, secondaryZoneKey].filter(Boolean) as string[];

  const parseKey = (key: string) => {
    if (key === 'Bull') return { val: 25, mult: Multiplier.Single };
    if (key === 'D-Bull') return { val: 25, mult: Multiplier.Double };
    const multLabel = key.match(/^[DT]/)?.[0] || '';
    const val = parseInt(key.replace(/^[DT]/, ''));
    const mult = multLabel === 'D' ? Multiplier.Double : multLabel === 'T' ? Multiplier.Triple : Multiplier.Single;
    return { val, mult };
  };

  const targets = targetKeys.map(parseKey);

  // 2. Proximity Helpers
  const getNeighbors = (val: number) => {
    if (val === 25) return DARTBOARD_NUMBERS; // Everything neighbors center in a way, but we simplify
    const idx = DARTBOARD_NUMBERS.indexOf(val);
    const prev = DARTBOARD_NUMBERS[(idx - 1 + 20) % 20];
    const next = DARTBOARD_NUMBERS[(idx + 1) % 20];
    return [prev, next];
  };

  const getRadialDistance = (m1: Multiplier, m2: Multiplier) => {
    // Distance between rings: Double(2) -> Single(1) -> Triple(3) -> Single(1) -> Bull
    // We treat Single as having two zones: Inner and Outer. 
    // This is a simplified distance matrix for precision scoring
    if (m1 === m2) return 0;
    return Math.abs(m1 - m2); 
  };

  // 3. Precision & Grouping Logic
  let totalPrecisionScore = 0;

  playerThrows.forEach(t => {
    let bestThrowScore = 0;

    targets.forEach(target => {
      let currentScore = 0;
      const neighbors = getNeighbors(target.val);

      const isSameNum = t.scoreValue === target.val;
      const isNeighborNum = neighbors.includes(t.scoreValue);

      if (isSameNum) {
        if (t.multiplier === target.mult) {
          currentScore = 100; // Perfect
        } else {
          // Same number, check ring adjacency
          const dist = getRadialDistance(t.multiplier, target.mult);
          currentScore = dist === 1 ? 85 : 60; 
        }
      } else if (isNeighborNum) {
        if (t.multiplier === target.mult) {
          currentScore = 50; // Neighbor, same ring
        } else {
          const dist = getRadialDistance(t.multiplier, target.mult);
          currentScore = dist === 1 ? 30 : 10;
        }
      } else if (target.val === 25 && t.scoreValue !== 0) {
        // Aiming bull, hit anything else is low precision
        currentScore = 5;
      }

      if (currentScore > bestThrowScore) bestThrowScore = currentScore;
    });

    totalPrecisionScore += bestThrowScore;
  });

  const finalPrecision = Math.round(totalPrecisionScore / playerThrows.length);

  // Consistency / Grouping Calculation (tightness of shots)
  // We check how many darts fall in the same segment or adjacent ones regardless of target
  let groupScore = 0;
  playerThrows.forEach((t1, i) => {
    playerThrows.forEach((t2, j) => {
      if (i === j) return;
      if (t1.scoreValue === t2.scoreValue) groupScore += t1.multiplier === t2.multiplier ? 1 : 0.7;
      else if (getNeighbors(t1.scoreValue).includes(t2.scoreValue)) groupScore += 0.4;
    });
  });
  const groupingIndex = Math.min(100, Math.round((groupScore / (playerThrows.length * (playerThrows.length - 1 || 1))) * 100 * 2));

  const getStatus = () => {
    if (finalPrecision > 75) return { label: 'Sniper', color: 'bg-emerald-500' };
    if (groupingIndex > 70) return { label: 'Régulier', color: 'bg-blue-500' };
    if (finalPrecision > 40) return { label: 'Correct', color: 'bg-amber-500' };
    return { label: 'Débutant', color: 'bg-slate-400' };
  };

  const status = getStatus();

  return (
    <div className="mt-4 p-5 bg-white dark:bg-slate-900 rounded-3xl border border-slate-100 dark:border-slate-800 shadow-sm">
      <div className="flex justify-between items-start mb-6">
        <div>
          <span className="text-[10px] font-black uppercase tracking-[0.2em] text-slate-400 dark:text-slate-500 block mb-2">Profil de tir</span>
          <div className="flex items-center gap-2">
            <span className={`px-3 py-1 ${status.color} text-white text-[10px] font-black uppercase tracking-widest rounded-full shadow-sm`}>
              {status.label}
            </span>
            {targetKeys.map(key => (
              <span key={key} className="px-3 py-1 bg-slate-100 dark:bg-slate-800 text-slate-600 dark:text-slate-400 text-[10px] font-bold rounded-full border border-slate-200 dark:border-slate-700">
                Cible: {key}
              </span>
            ))}
          </div>
        </div>
        <div className="text-right">
          <div className="text-4xl font-black text-slate-800 dark:text-white tracking-tighter leading-none">
            {finalPrecision}<span className="text-lg opacity-30 ml-0.5">%</span>
          </div>
          <span className="text-[10px] font-bold uppercase text-slate-400 dark:text-slate-500">Précision Globale</span>
        </div>
      </div>

      <div className="space-y-4">
        {/* Precision Bar */}
        <div>
          <div className="flex justify-between text-[10px] font-bold uppercase tracking-widest mb-1.5">
            <span className="text-slate-400">Précision</span>
            <span className="text-emerald-500">{finalPrecision}%</span>
          </div>
          <div className="h-2 w-full bg-slate-100 dark:bg-slate-800 rounded-full overflow-hidden">
            <div 
              className="h-full bg-emerald-500 transition-all duration-1000 ease-out"
              style={{ width: `${finalPrecision}%` }}
            />
          </div>
        </div>

        {/* Grouping Bar */}
        <div>
          <div className="flex justify-between text-[10px] font-bold uppercase tracking-widest mb-1.5">
            <span className="text-slate-400">Groupement (Tightness)</span>
            <span className="text-blue-500">{groupingIndex}%</span>
          </div>
          <div className="h-2 w-full bg-slate-100 dark:bg-slate-800 rounded-full overflow-hidden">
            <div 
              className="h-full bg-blue-500 transition-all duration-1000 ease-out"
              style={{ width: `${groupingIndex}%` }}
            />
          </div>
        </div>
      </div>

      <div className="mt-6 pt-4 border-t border-slate-50 dark:border-slate-800 flex justify-around text-center">
        <div>
            <div className="text-xs font-black text-slate-800 dark:text-white">{playerThrows.length}</div>
            <div className="text-[8px] font-bold uppercase text-slate-400 tracking-widest">Dards</div>
        </div>
        <div className="w-px h-8 bg-slate-100 dark:bg-slate-800"></div>
        <div>
            <div className="text-xs font-black text-slate-800 dark:text-white">
                {Math.round(playerThrows.filter(t => targets.some(tgt => tgt.val === t.scoreValue)).length / playerThrows.length * 100)}%
            </div>
            <div className="text-[8px] font-bold uppercase text-slate-400 tracking-widest">Numéro Visé</div>
        </div>
        <div className="w-px h-8 bg-slate-100 dark:bg-slate-800"></div>
        <div>
            <div className="text-xs font-black text-slate-800 dark:text-white">
                {playerThrows.filter(t => t.isBust).length}
            </div>
            <div className="text-[8px] font-bold uppercase text-slate-400 tracking-widest">Busts</div>
        </div>
      </div>
    </div>
  );
};

import React from 'react';
import { Throw, Multiplier } from '../types';
import { DARTBOARD_NUMBERS, getMultiplierLabel } from '../constants';

interface PrecisionAnalysisProps {
  history: Throw[];
  playerId: string;
}

export const PrecisionAnalysis: React.FC<PrecisionAnalysisProps> = ({ history, playerId }) => {
  const playerThrows = history.filter(t => t.playerId === playerId);
  if (playerThrows.length === 0) return null;

  // 1. Target Detection based on Numbers (Cells)
  const numberCounts: Record<number, number> = {};
  playerThrows.forEach(t => {
    numberCounts[t.scoreValue] = (numberCounts[t.scoreValue] || 0) + 1;
  });

  const sortedNumbers = Object.entries(numberCounts)
    .map(([val, count]) => ({ val: parseInt(val), count }))
    .sort((a, b) => b.count - a.count);

  const primaryNum = sortedNumbers[0].val;
  const primaryCount = sortedNumbers[0].count;

  let secondaryNum: number | null = null;
  if (sortedNumbers.length > 1 && sortedNumbers[1].count >= primaryCount * 0.25) {
    secondaryNum = sortedNumbers[1].val;
  }

  const targetNumbers = [primaryNum, secondaryNum].filter(n => n !== null) as number[];

  // For visual feedback, find the most common multiplier for each target number
  const getTopSegmentLabel = (num: number) => {
    const multCounts: Record<number, number> = {};
    playerThrows.filter(t => t.scoreValue === num).forEach(t => {
        multCounts[t.multiplier] = (multCounts[t.multiplier] || 0) + 1;
    });
    const topMult = parseInt(Object.entries(multCounts).sort((a, b) => b[1] - a[1])[0][0]);
    if (num === 25) return topMult === 2 ? 'D-BULL' : 'BULL';
    return `${getMultiplierLabel(topMult as Multiplier)}${num}`;
  };

  // 2. Proximity Helpers
  const getNeighbors = (val: number) => {
    if (val === 25 || val === 0) return [];
    const idx = DARTBOARD_NUMBERS.indexOf(val);
    const prev = DARTBOARD_NUMBERS[(idx - 1 + 20) % 20];
    const next = DARTBOARD_NUMBERS[(idx + 1) % 20];
    return [prev, next];
  };

  // 3. New Precision Scoring Logic (Focused on the Number)
  let totalPrecisionScore = 0;

  playerThrows.forEach(t => {
    let bestThrowScore = 0;

    targetNumbers.forEach(targetVal => {
      let currentScore = 0;
      const neighbors = getNeighbors(targetVal);

      if (t.scoreValue === targetVal) {
        // Correct number! 
        // We give almost full points even if multiplier is wrong
        // because the user hit the right "cell" / longitudinal zone.
        const targetMultForThisNum = playerThrows
            .filter(throwObj => throwObj.scoreValue === targetVal)
            .reduce((acc, curr) => (acc.count > (acc.map[curr.multiplier] || 0) ? acc : {count: (acc.map[curr.multiplier] || 0) + 1, map: {...acc.map, [curr.multiplier]: (acc.map[curr.multiplier] || 0) + 1}}), {count: 0, map: {} as Record<number, number>})
            // This is a bit complex, let's just compare with the throw's own multiplier if we want simple bonus

        currentScore = 100; // Hit the right number

        // Small penalty if the multiplier is very different from common hits, but keep it high
        // If it's a miss-hit on the same number, it's 92% (High precision as requested)
      } else if (neighbors.includes(t.scoreValue)) {
        currentScore = 45; // Hit neighbor (lateral error)
      } else if (targetVal === 25 && t.scoreValue !== 0) {
        currentScore = 10; // Aiming bull, hit something else
      }

      if (currentScore > bestThrowScore) bestThrowScore = currentScore;
    });

    totalPrecisionScore += bestThrowScore;
  });

  const finalPrecision = Math.round(totalPrecisionScore / playerThrows.length);

  // Grouping (Consistency) - Independent of targets
  let groupScore = 0;
  playerThrows.forEach((t1, i) => {
    playerThrows.forEach((t2, j) => {
      if (i === j) return;
      if (t1.scoreValue === t2.scoreValue) groupScore += 1; // Same cell = Max grouping
      else if (getNeighbors(t1.scoreValue).includes(t2.scoreValue)) groupScore += 0.5;
    });
  });
  const groupingIndex = Math.min(100, Math.round((groupScore / (playerThrows.length * (playerThrows.length - 1 || 1))) * 100 * 1.5));

  const getStyle = () => {
    if (finalPrecision > 85) return { label: 'Maître', color: 'bg-emerald-500', icon: '🎯' };
    if (finalPrecision > 65) return { label: 'Précis', color: 'bg-emerald-400', icon: '✨' };
    if (groupingIndex > 75) return { label: 'Constant', color: 'bg-blue-500', icon: '📏' };
    return { label: 'En progression', color: 'bg-slate-400', icon: '📈' };
  };

  const style = getStyle();

  return (
    <div className="mt-4 p-6 bg-slate-50 dark:bg-slate-900/50 rounded-[2rem] border border-slate-100 dark:border-slate-800 shadow-inner">
      <div className="flex flex-col md:flex-row justify-between items-center gap-6 mb-8">
        <div className="text-center md:text-left">
          <span className="text-[10px] font-black uppercase tracking-[0.3em] text-slate-400 block mb-3">Analyse Tactique</span>
          <div className="flex flex-wrap justify-center md:justify-start gap-2">
            <div className={`flex items-center gap-2 px-4 py-1.5 ${style.color} text-white rounded-full shadow-lg`}>
              <span className="text-sm">{style.icon}</span>
              <span className="text-xs font-black uppercase tracking-widest">{style.label}</span>
            </div>
            {targetNumbers.map(num => (
              <div key={num} className="px-4 py-1.5 bg-white dark:bg-slate-800 text-slate-600 dark:text-slate-300 rounded-full border border-slate-200 dark:border-slate-700 text-xs font-bold shadow-sm">
                Focus : <span className="text-emerald-500">#{num}</span>
              </div>
            ))}
          </div>
        </div>

        <div className="relative flex items-center justify-center">
            <svg className="w-24 h-24 transform -rotate-90">
                <circle cx="48" cy="48" r="40" stroke="currentColor" strokeWidth="8" fill="transparent" className="text-slate-200 dark:text-slate-800" />
                <circle cx="48" cy="48" r="40" stroke="currentColor" strokeWidth="8" fill="transparent" strokeDasharray={251.2} strokeDashoffset={251.2 * (1 - finalPrecision / 100)} className="text-emerald-500 transition-all duration-1000 ease-out" strokeLinecap="round" />
            </svg>
            <div className="absolute inset-0 flex flex-col items-center justify-center">
                <span className="text-2xl font-black text-slate-800 dark:text-white leading-none">{finalPrecision}%</span>
                <span className="text-[8px] font-bold text-slate-400 uppercase tracking-tighter">Précision</span>
            </div>
        </div>
      </div>

      <div className="space-y-6">
        {/* Grouping Index */}
        <div>
          <div className="flex justify-between items-center mb-2">
