    return [prev, next];
  };

  const allTargetNeighbors = new Set<number>();
  targetNumbers.forEach(num => {
    getNeighbors(num).forEach(n => allTargetNeighbors.add(n));
  });

  // 3. Score Calculation
  // Rule: Target Zone = 100% | Neighbor = 40% | Other = 0%
  let totalScore = 0;
  playerThrows.forEach(t => {
    if (targetNumbers.includes(t.scoreValue)) {
      totalScore += 100;
    } else if (allTargetNeighbors.has(t.scoreValue)) {
      totalScore += 40;
    } else {
      totalScore += 0;
    }
  });

  const finalPrecision = Math.round(totalScore / playerThrows.length);

  return (
    <div className="mt-4 p-6 bg-slate-50 dark:bg-slate-900/50 rounded-[2rem] border border-slate-100 dark:border-slate-800">
      <div className="flex flex-col md:flex-row justify-between items-center gap-6 mb-8">
        <div className="text-center md:text-left">
          <span className="text-[10px] font-black uppercase tracking-[0.3em] text-slate-400 block mb-3">Zones visées détectées</span>
          <div className="flex flex-wrap justify-center md:justify-start gap-2">
            {targetNumbers.map(num => (
              <div key={num} className="px-5 py-2 bg-white dark:bg-slate-800 text-slate-800 dark:text-white rounded-2xl border border-slate-200 dark:border-slate-700 text-sm font-black shadow-sm">
                Case <span className="text-emerald-500">#{num === 25 ? 'BULL' : num}</span>
              </div>
            ))}
          </div>
        </div>

        <div className="relative flex items-center justify-center">
            <svg className="w-24 h-24 transform -rotate-90">
                <circle cx="48" cy="48" r="40" stroke="currentColor" strokeWidth="10" fill="transparent" className="text-slate-200 dark:text-slate-800" />
                <circle 
                  cx="48" 
                  cy="48" 
                  r="40" 
                  stroke="currentColor" 
                  strokeWidth="10" 
                  fill="transparent" 
                  strokeDasharray={251.2} 
                  strokeDashoffset={251.2 * (1 - finalPrecision / 100)} 
                  className="text-emerald-500 transition-all duration-1000 ease-out" 
                  strokeLinecap="round" 
                />
            </svg>
            <div className="absolute inset-0 flex flex-col items-center justify-center">
                <span className="text-2xl font-black text-slate-800 dark:text-white leading-none">{finalPrecision}</span>
                <span className="text-[8px] font-bold text-slate-400 uppercase tracking-tighter">Score / 100</span>
            </div>
        </div>
      </div>

      <div className="grid grid-cols-3 gap-2 pt-6 border-t border-slate-200/50 dark:border-slate-800">
          <div className="text-center">
              <div className="text-lg font-black text-slate-800 dark:text-white">{playerThrows.length}</div>
              <div className="text-[8px] font-bold text-slate-400 uppercase tracking-widest">Tirs</div>
          </div>
          <div className="text-center border-x border-slate-200/50 dark:border-slate-800">
              <div className="text-lg font-black text-emerald-500">
                  {playerThrows.filter(t => targetNumbers.includes(t.scoreValue)).length}
              </div>
              <div className="text-[8px] font-bold text-slate-400 uppercase tracking-widest">Dans la zone</div>
          </div>
          <div className="text-center">
              <div className="text-lg font-black text-blue-500">
                  {playerThrows.filter(t => allTargetNeighbors.has(t.scoreValue)).length}
              </div>
              <div className="text-[8px] font-bold text-slate-400 uppercase tracking-widest">Voisins</div>
          </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useCallback } from 'react';
import { GameStatus, GameConfig, GameState, Player, Throw, Multiplier } from './types';
import { MAX_THROWS_PER_TURN } from './constants';
import { Setup } from './components/Setup';
import { Scoreboard } from './components/Scoreboard';
import { InputPad } from './components/InputPad';
import { DartboardHeatmap } from './components/DartboardHeatmap';
import { PrecisionAnalysis } from './components/PrecisionAnalysis';

const App: React.FC = () => {
  const [isDarkMode, setIsDarkMode] = useState<boolean>(false);
  const [config, setConfig] = useState<GameConfig | null>(null);
  const [state, setState] = useState<GameState>({
    status: GameStatus.Setup,
    currentLeg: 1,
    currentPlayerIndex: 0,
    legStarterIndex: 0,
    turnThrows: [],
    history: [],
    scoreAtStartOfTurn: 0,
    finishedPlayerIds: [],
  });
  const [players, setPlayers] = useState<Player[]>([]);
  const [showBullAnimation, setShowBullAnimation] = useState<boolean>(false);
  const [showDoubleBullAnimation, setShowDoubleBullAnimation] = useState<boolean>(false);
  const [showWinAnimation, setShowWinAnimation] = useState<boolean>(false);
  const [isShaking, setIsShaking] = useState<boolean>(false);

  useEffect(() => {
    if (isDarkMode) document.documentElement.classList.add('dark');
    else document.documentElement.classList.remove('dark');
  }, [isDarkMode]);

  const toggleTheme = () => setIsDarkMode(!isDarkMode);

  const triggerShake = (intensity: 'light' | 'heavy' = 'light') => {
    setIsShaking(true);
    setTimeout(() => setIsShaking(false), intensity === 'light' ? 400 : 600);
  };

  const playBustSound = () => {
    try {
      const AudioContext = window.AudioContext || (window as any).webkitAudioContext;
      const ctx = new AudioContext();
      const osc1 = ctx.createOscillator();
      const osc2 = ctx.createOscillator();
      const gain = ctx.createGain();
      osc1.type = 'sawtooth'; osc2.type = 'square';
      osc1.frequency.setValueAtTime(120, ctx.currentTime);
      osc2.frequency.setValueAtTime(126, ctx.currentTime);
      gain.gain.setValueAtTime(0.2, ctx.currentTime);
      gain.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + 0.5);
      osc1.connect(gain); osc2.connect(gain); gain.connect(ctx.destination);
      osc1.start(); osc2.start();
      osc1.stop(ctx.currentTime + 0.5); osc2.stop(ctx.currentTime + 0.5);
    } catch (e) {}
  };

  const playWinSound = () => {
    try {
      const AudioContext = window.AudioContext || (window as any).webkitAudioContext;
      const ctx = new AudioContext();
      const gain = ctx.createGain();
      gain.connect(ctx.destination);
      gain.gain.setValueAtTime(0.1, ctx.currentTime);
      const playNote = (freq: number, start: number, duration: number) => {
        const osc = ctx.createOscillator();
        osc.type = 'sine';
        osc.frequency.setValueAtTime(freq, ctx.currentTime + start);
        const noteGain = ctx.createGain();
        noteGain.gain.setValueAtTime(0, ctx.currentTime + start);
        noteGain.gain.linearRampToValueAtTime(0.2, ctx.currentTime + start + 0.05);
        noteGain.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + start + duration);
        osc.connect(noteGain); noteGain.connect(gain);
        osc.start(ctx.currentTime + start); osc.stop(ctx.currentTime + start + duration);
      };
      playNote(523.25, 0, 0.4); playNote(659.25, 0.15, 0.4); playNote(783.99, 0.3, 0.4); playNote(1046.50, 0.45, 1.2);
    } catch (e) {}
  };

  const startGame = (newConfig: GameConfig) => {
    setConfig(newConfig);
    setPlayers(newConfig.players);
    setState({
      status: GameStatus.Playing,
      currentLeg: 1,
      currentPlayerIndex: 0,
      legStarterIndex: 0,
      turnThrows: [],
      history: [],
      scoreAtStartOfTurn: newConfig.players[0].score,
      finishedPlayerIds: [],
    });
    setShowWinAnimation(false);
  };

  const getNextPlayerIndex = (currentIndex: number, allPlayers: Player[], finished: string[]) => {
    let next = (currentIndex + 1) % allPlayers.length;
    while (finished.includes(allPlayers[next].id)) {
      next = (next + 1) % allPlayers.length;
      if (next === currentIndex) break;
    }
    return next;
  };

  const handleTurnEnd = useCallback((playersSnapshot?: Player[], finishedSnapshot?: string[]) => {
    if (!config) return;
    const currentPlayers = playersSnapshot || players;
    const finished = finishedSnapshot || state.finishedPlayerIds;

    setState((prev) => {
        const nextIdx = getNextPlayerIndex(prev.currentPlayerIndex, currentPlayers, finished);
        return {
            ...prev,
            turnThrows: [],
            currentPlayerIndex: nextIdx,
            scoreAtStartOfTurn: currentPlayers[nextIdx].score,
        };
    });
  }, [config, players, state.finishedPlayerIds]);

  const handleThrow = (value: number, multiplier: Multiplier) => {
    if (state.status !== GameStatus.Playing || !config || showWinAnimation) return;

    if (value === 25) {
      if (multiplier === Multiplier.Double) { 
        setShowDoubleBullAnimation(true); 
        triggerShake('heavy');
        setTimeout(() => setShowDoubleBullAnimation(false), 1500); 
      }
      else { 
        setShowBullAnimation(true); 
        triggerShake('light');
        setTimeout(() => setShowBullAnimation(false), 1200); 
      }
    }

    const currentPlayer = players[state.currentPlayerIndex];
    const points = value * multiplier;
    const newScore = currentPlayer.score - points;
    const now = Date.now();

    let isBust = newScore < 0;
    let isWin = newScore === 0;

    const newThrow: Throw = {
      playerId: currentPlayer.id,
      legId: state.currentLeg,
      scoreValue: value,
      multiplier,
      totalPoints: points,
      isBust,
      isWin,
      timestamp: now,
    };

    const updatedPlayers = [...players];
    if (isBust) {
      updatedPlayers[state.currentPlayerIndex].score = state.scoreAtStartOfTurn;
      playBustSound();
      triggerShake('light');
    } else {
      updatedPlayers[state.currentPlayerIndex].score = newScore;
    }
    setPlayers(updatedPlayers);

    let newFinished = [...state.finishedPlayerIds];
    if (isWin) {
        newFinished.push(currentPlayer.id);
        playWinSound();
        setShowWinAnimation(true);
        triggerShake('heavy');
        setTimeout(() => setShowWinAnimation(false), 2000);
    }

    setState((prev) => ({
        ...prev,
        turnThrows: [...prev.turnThrows, newThrow],
        history: [...prev.history, newThrow],
        finishedPlayerIds: newFinished,
    }));

    if (newFinished.length >= players.length - 1) {
        const lastPlayer = players.find(p => !newFinished.includes(p.id));
        if (lastPlayer && !newFinished.includes(lastPlayer.id)) {
            newFinished.push(lastPlayer.id);
        }
        setTimeout(() => setState(prev => ({ ...prev, status: GameStatus.Summary, finishedPlayerIds: newFinished })), 2500);
        return;
    }

    if (isBust || isWin || state.turnThrows.length + 1 >= MAX_THROWS_PER_TURN) {
      setTimeout(() => handleTurnEnd(updatedPlayers, newFinished), isBust || isWin ? 800 : 500);
    }
  };

  const handleUndo = () => {
    if (state.history.length === 0 || !config) return;
    const newHistory = [...state.history];
    const undoneThrow = newHistory.pop()!;

    const updatedPlayers = players.map(player => {
        const pHistory = newHistory.filter(t => t.playerId === player.id && t.legId === state.currentLeg);
        let curScore = config.startingScore;
        let turnStart = config.startingScore;
        let dartCount = 0;
        for (const t of pHistory) {
            if (dartCount === 0) turnStart = curScore;
            if (t.isBust) { curScore = turnStart; dartCount = 0; }
            else { curScore -= t.totalPoints; dartCount++; if (dartCount >= 3) dartCount = 0; }
        }
        return { ...player, score: curScore };
    });
    setPlayers(updatedPlayers);

    const newFinished = state.finishedPlayerIds.filter(id => {
        if (id === undoneThrow.playerId && undoneThrow.isWin) return false;
        return true;
    });

    const pIndex = players.findIndex(p => p.id === undoneThrow.playerId);
    const pNewHist = newHistory.filter(t => t.playerId === undoneThrow.playerId && t.legId === state.currentLeg);
    const lastTurnThrows: Throw[] = [];
    let turnCount = 0;
    for (const t of pNewHist) {
        lastTurnThrows.push(t); turnCount++;
        if (turnCount >= 3 || t.isBust) { lastTurnThrows.length = 0; turnCount = 0; }
    }
    const unfinishedPoints = lastTurnThrows.reduce((s, t) => s + t.totalPoints, 0);

    setState(prev => ({
        ...prev,
        status: GameStatus.Playing,
        currentPlayerIndex: pIndex,
        turnThrows: lastTurnThrows,
        history: newHistory,
        scoreAtStartOfTurn: updatedPlayers[pIndex].score + unfinishedPoints,
        finishedPlayerIds: newFinished,
    }));
  };

  const restartMatch = () => startGame({ ...config!, players: players.map(p => ({ ...p, score: config!.startingScore, wins: 0 })) });
  const newGame = () => setState(prev => ({ ...prev, status: GameStatus.Setup }));

  const ThemeToggle = () => (
    <button onClick={toggleTheme} className="p-2 rounded-full bg-slate-200 dark:bg-slate-800 text-slate-600 dark:text-slate-300 transition-colors">
        {isDarkMode ? '🌙' : '☀️'}
    </button>
  );

  if (state.status === GameStatus.Setup) return (
    <div className="min-h-screen bg-slate-50 dark:bg-slate-950 flex flex-col items-center justify-center p-4">
        <div className="absolute top-4 right-4"><ThemeToggle /></div>
        <Setup onStartGame={startGame} />
    </div>
  );

  if (state.status === GameStatus.Summary) {
    return (
      <div className="min-h-screen bg-slate-50 dark:bg-slate-950 p-4">
        <div className="absolute top-4 right-4"><ThemeToggle /></div>
        <div className="max-w-4xl mx-auto">
            <h1 className="text-4xl font-black text-center text-emerald-500 mb-8">CLASSEMENT FINAL</h1>
            <div className="grid gap-4 mb-8">
                {state.finishedPlayerIds.map((id, index) => {
                    const p = players.find(player => player.id === id)!;
                    const darts = state.history.filter(t => t.playerId === id).length;
                    return (
                        <div key={id} className={`flex flex-col gap-4 p-6 rounded-2xl bg-white dark:bg-slate-800 shadow-lg border-l-8 ${index === 0 ? 'border-emerald-500' : 'border-slate-300'}`}>
                            <div className="flex items-center gap-4">
                                <div className="text-3xl font-black text-slate-400 w-12">{index + 1}e</div>
                                <div className="flex-1">
                                    <div className="text-xl font-bold">{p.name}</div>
                                    <div className="text-xs text-slate-500 font-bold uppercase">{darts} fléchettes • Moy: {Math.round((config!.startingScore / (Math.max(1, darts)/3)))}</div>
                                </div>
                                {index === 0 && <div className="text-3xl">🏆</div>}
                            </div>

                            <div className="grid md:grid-cols-2 gap-4 items-center">
                                <div className="w-full h-auto">
                                    <DartboardHeatmap history={state.history} playerId={id} isDarkMode={isDarkMode} />
                                </div>
                                <PrecisionAnalysis history={state.history} playerId={id} />
                            </div>
                        </div>
                    );
                })}
            </div>
            <div className="flex justify-center gap-4">
                <button onClick={restartMatch} className="bg-emerald-500 text-white px-8 py-3 rounded-xl font-bold shadow-lg">Rejouer</button>
                <button onClick={newGame} className="bg-white dark:bg-slate-700 text-slate-700 dark:text-white px-8 py-3 rounded-xl font-bold border border-slate-200 dark:border-slate-600">Nouveau setup</button>
            </div>
        </div>
      </div>
    );
  }

  const currentPlayer = players[state.currentPlayerIndex];

  return (
    <div className={`min-h-screen bg-slate-50 dark:bg-slate-950 p-4 flex flex-col transition-colors relative overflow-hidden ${isShaking ? 'animate-shake' : ''}`}>
      {showBullAnimation && (
        <div className="fixed inset-0 z-50 flex items-center justify-center pointer-events-none">
          <div className="shockwave bg-red-500/20"></div>
          <div className="animate-bull-blast flex flex-col items-center">
            <div className="bg-red-600 text-white font-black text-7xl px-12 py-8 rounded-[3rem] shadow-[0_0_50px_rgba(220,38,38,0.5)] border-4 border-white/20">BULL!</div>
          </div>
        </div>
      )}

      {showDoubleBullAnimation && (
        <div className="fixed inset-0 z-50 flex items-center justify-center pointer-events-none">
          <div className="shockwave bg-amber-400/30"></div>
          <div className="shockwave bg-white/20" style={{ animationDelay: '0.1s' }}></div>
          <div className="animate-dbull-blast flex flex-col items-center">
            <div className="bg-amber-500 text-white font-black text-7xl px-12 py-8 rounded-[3rem] shadow-[0_0_70px_rgba(245,158,11,0.6)] border-4 border-white/30 animate-gold-pulse uppercase italic tracking-tighter">
              D-BULL!
            </div>
          </div>
        </div>
      )}

      {showWinAnimation && (
        <div className="fixed inset-0 z-[60] flex items-center justify-center pointer-events-none">
            <div className="absolute inset-0 bg-emerald-500/80 backdrop-blur-md"></div>
            <div className="animate-winner-pop text-center">
                <h2 className="text-2xl text-white font-bold mb-2 uppercase tracking-widest">Joueur qualifié !</h2>
                <div className="bg-white text-emerald-600 font-black text-6xl px-12 py-6 rounded-3xl shadow-2xl">{currentPlayer.name}</div>
                <div className="mt-4 text-white text-4xl font-black"># {state.finishedPlayerIds.length}</div>
            </div>
        </div>
      )}

      <header className="flex justify-between items-center mb-4 max-w-md mx-auto w-full">
        <h1 className="font-bold text-slate-400 uppercase text-xs">Leg {state.currentLeg}</h1>
        <div className="flex items-center gap-4">
            <ThemeToggle />
            <button onClick={newGame} className="text-xs text-slate-500 font-bold">Quitter</button>
        </div>
      </header>

      <main className="flex-1 flex flex-col justify-center">
        <Scoreboard 
          players={players} 
          currentPlayerId={currentPlayer.id} 
          currentTurnThrows={state.turnThrows} 
          scoreAtStartOfTurn={state.scoreAtStartOfTurn} 
          history={state.history}
          finishedPlayerIds={state.finishedPlayerIds}
        />
        <InputPad onSubmitThrow={handleThrow} onUndo={handleUndo} canUndo={state.history.length > 0} />
      </main>
    </div>
  );
};

export default App;

import React from 'react';
import { Throw } from '../types';
import { DARTBOARD_NUMBERS } from '../constants';

interface PrecisionAnalysisProps {
  history: Throw[];
  playerId: string;
}

export const PrecisionAnalysis: React.FC<PrecisionAnalysisProps> = ({ history, playerId }) => {
  const playerThrows = history.filter(t => t.playerId === playerId);
  if (playerThrows.length === 0) return null;

  // 1. Target Detection (Strictly by Number/Cell)
  const numberCounts: Record<number, number> = {};
  playerThrows.forEach(t => {
    numberCounts[t.scoreValue] = (numberCounts[t.scoreValue] || 0) + 1;
  });

  const sortedNumbers = Object.entries(numberCounts)
    .map(([val, count]) => ({ val: parseInt(val), count }))
    .sort((a, b) => b.count - a.count);

  if (sortedNumbers.length === 0) return null;

  const primaryNum = sortedNumbers[0].val;
  const primaryCount = sortedNumbers[0].count;

  // Secondary zone if it represents at least 25% of the primary zone's hits
  let secondaryNum: number | null = null;
  if (sortedNumbers.length > 1 && sortedNumbers[1].count >= primaryCount * 0.25) {
    secondaryNum = sortedNumbers[1].val;
  }

  const targetNumbers = [primaryNum, secondaryNum].filter(n => n !== null) as number[];

  // 2. Neighbor Logic
  const getNeighbors = (val: number) => {
    if (val === 0) return [];
    if (val === 25) return []; // Bull is center
    const idx = DARTBOARD_NUMBERS.indexOf(val);
    const prev = DARTBOARD_NUMBERS[(idx - 1 + 20) % 20];
    const next = DARTBOARD_NUMBERS[(idx + 1) % 20];
    return [prev, next];
  };

  const allTargetNeighbors = new Set<number>();
  targetNumbers.forEach(num => {
    getNeighbors(num).forEach(n => allTargetNeighbors.add(n));
  });

  // 3. Score Calculation
  // Rule: Target Zone = 100% | Neighbor = 40% | Other = 0%
  let totalScore = 0;
  playerThrows.forEach(t => {
    if (targetNumbers.includes(t.scoreValue)) {
      totalScore += 100;
    } else if (allTargetNeighbors.has(t.scoreValue)) {
      totalScore += 40;
    } else {
      totalScore += 0;
    }
  });

  const finalPrecision = Math.round(totalScore / playerThrows.length);

  // Dynamic Color based on precision
  const getPrecisionColor = (score: number) => {
    if (score >= 70) return 'text-emerald-500';
    if (score >= 40) return 'text-amber-500';
    return 'text-rose-500';
  };

  const getStrokeColor = (score: number) => {
    if (score >= 70) return 'stroke-emerald-500';
    if (score >= 40) return 'stroke-amber-500';
    return 'stroke-rose-500';
  };

  return (
    <div className="mt-4 p-8 bg-white dark:bg-slate-900 rounded-[2.5rem] border border-slate-100 dark:border-slate-800 shadow-xl shadow-slate-200/50 dark:shadow-none">
      <div className="flex flex-col items-center gap-8">

        {/* Main Precision Display */}
        <div className="relative flex items-center justify-center scale-110">
            <svg className="w-40 h-40 transform -rotate-90">
                {/* Background Track */}
                <circle 
                  cx="80" cy="80" r="72" 
                  stroke="currentColor" 
                  strokeWidth="12" 
                  fill="transparent" 
                  className="text-slate-100 dark:text-slate-800" 
                />
                {/* Progress Ring */}
                <circle 
                  cx="80" cy="80" r="72" 
                  stroke="currentColor" 
                  strokeWidth="12" 
                  fill="transparent" 
                  strokeDasharray={452.4} 
                  strokeDashoffset={452.4 * (1 - finalPrecision / 100)} 
                  className={`${getStrokeColor(finalPrecision)} transition-all duration-1000 ease-out`} 
                  strokeLinecap="round" 
                />
            </svg>
            <div className="absolute inset-0 flex flex-col items-center justify-center">
                <div className={`text-5xl font-black tracking-tighter leading-none ${getPrecisionColor(finalPrecision)}`}>
                  {finalPrecision}<span className="text-xl ml-0.5 opacity-50">%</span>
                </div>
                <div className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] mt-2">
                  Précision
                </div>
            </div>
        </div>

        {/* Targets Display */}
        <div className="w-full text-center">
          <span className="text-[9px] font-black uppercase tracking-[0.4em] text-slate-300 dark:text-slate-600 block mb-4">Objectifs Identifiés</span>
          <div className="flex flex-wrap justify-center gap-3">
            {targetNumbers.map(num => (
              <div key={num} className="px-6 py-2.5 bg-slate-50 dark:bg-slate-800 text-slate-800 dark:text-white rounded-2xl border border-slate-200 dark:border-slate-700 text-sm font-black shadow-sm flex items-center gap-2">
                <div className={`w-2 h-2 rounded-full ${getStrokeColor(finalPrecision).replace('stroke', 'bg')}`}></div>
                Case <span className="text-emerald-500">#{num === 25 ? 'BULL' : num}</span>
              </div>
            ))}
          </div>
        </div>
      </div>

      {/* Stats Breakdown */}
      <div className="grid grid-cols-3 gap-4 pt-8 mt-8 border-t border-slate-100 dark:border-slate-800/50">
          <div className="text-center group">
              <div className="text-xl font-black text-slate-800 dark:text-white group-hover:scale-110 transition-transform">{playerThrows.length}</div>
              <div className="text-[9px] font-bold text-slate-400 uppercase tracking-widest mt-1">Total Tirs</div>
          </div>
          <div className="text-center border-x border-slate-100 dark:border-slate-800/50 group">
              <div className="text-xl font-black text-emerald-500 group-hover:scale-110 transition-transform">
                  {playerThrows.filter(t => targetNumbers.includes(t.scoreValue)).length}
              </div>
              <div className="text-[9px] font-bold text-slate-400 uppercase tracking-widest mt-1">Dans Zone</div>
          </div>
          <div className="text-center group">
              <div className="text-xl font-black text-blue-500 group-hover:scale-110 transition-transform">
                  {playerThrows.filter(t => allTargetNeighbors.has(t.scoreValue)).length}
              </div>
              <div className="text-[9px] font-bold text-slate-400 uppercase tracking-widest mt-1">Voisinage</div>
          </div>
      </div>
    </div>
  );
