import React, { useState } from 'react';
import { GameConfig, Player } from '../types';

interface SetupProps {
  onStartGame: (config: GameConfig) => void;
}

export const Setup: React.FC<SetupProps> = ({ onStartGame }) => {
  const [score, setScore] = useState<number>(301);
  const [legs, setLegs] = useState<number>(1); 
  const [playerNames, setPlayerNames] = useState<string[]>(['Player 1', 'Player 2']);
  const [draggedIndex, setDraggedIndex] = useState<number | null>(null);

  const addPlayer = () => {
    if (playerNames.length < 8) {
      setPlayerNames([...playerNames, `Player ${playerNames.length + 1}`]);
    }
  };

  const removePlayer = (index: number) => {
    if (playerNames.length > 1) {
      const newNames = playerNames.filter((_, i) => i !== index);
      setPlayerNames(newNames);
    }
  };

  const updateName = (index: number, name: string) => {
    const newNames = [...playerNames];
    newNames[index] = name;
    setPlayerNames(newNames);
  };

  const shufflePlayers = () => {
    const shuffled = [...playerNames].sort(() => Math.random() - 0.5);
    setPlayerNames(shuffled);
  };

  // Drag and Drop Logic
  const handleDragStart = (index: number) => {
    setDraggedIndex(index);
  };

  const handleDragEnter = (index: number) => {
    if (draggedIndex === null || draggedIndex === index) return;

    const newNames = [...playerNames];
    const itemToMove = newNames[draggedIndex];
    newNames.splice(draggedIndex, 1);
    newNames.splice(index, 0, itemToMove);

    setDraggedIndex(index);
    setPlayerNames(newNames);
  };

  const handleDragEnd = () => {
    setDraggedIndex(null);
  };

  const handleStart = () => {
    const players: Player[] = playerNames.map((name, index) => ({
      id: `p${index}-${Date.now()}`,
      name: name.trim() || `Player ${index + 1}`,
      score: score,
      wins: 0,
    }));

    onStartGame({
      startingScore: score,
      totalLegs: legs,
      players,
    });
  };

  return (
    <div className="max-w-md w-full mx-auto p-6 bg-white dark:bg-slate-800 rounded-3xl shadow-xl border border-slate-100 dark:border-slate-700 transition-all">
      <h1 className="text-3xl font-black text-center text-emerald-500 mb-8 tracking-tight italic">DARTSMASTER</h1>

      {/* Score Selection */}
      <div className="mb-6">
        <label className="block text-slate-400 dark:text-slate-500 mb-2 text-[10px] uppercase font-black tracking-[0.2em]">Starting Score</label>
        <div className="flex gap-3">
          {[301, 501].map((val) => (
            <button
              key={val}
              onClick={() => setScore(val)}
              className={`flex-1 py-3 rounded-2xl font-bold transition-all ${
                score === val 
                  ? 'bg-emerald-500 text-white shadow-lg shadow-emerald-200 dark:shadow-emerald-900/30' 
                  : 'bg-slate-50 dark:bg-slate-700/50 text-slate-500 dark:text-slate-400 hover:bg-slate-100 dark:hover:bg-slate-700'
              }`}
            >
              {val}
            </button>
          ))}
          <input
            type="number"
            value={score}
            onChange={(e) => setScore(parseInt(e.target.value) || 0)}
            className="w-20 bg-slate-50 dark:bg-slate-700/50 rounded-2xl px-2 text-center text-slate-800 dark:text-white font-bold focus:outline-none focus:ring-2 focus:ring-emerald-500 transition-all"
            placeholder="Custom"
          />
        </div>
      </div>

      {/* Legs */}
      <div className="mb-6">
        <label className="block text-slate-400 dark:text-slate-500 mb-2 text-[10px] uppercase font-black tracking-[0.2em]">Format (Best of X)</label>
