export enum Multiplier {
  Single = 1,
  Double = 2,
  Triple = 3,
}

export interface Throw {
  playerId: string;
  legId: number;
  scoreValue: number;
  multiplier: Multiplier;
  totalPoints: number;
  isBust: boolean;
  isWin: boolean;
  timestamp: number;
}

export interface Player {
  id: string;
  name: string;
  score: number;
  wins: number; // This represents total legs won in the match
}

export enum GameStatus {
  Setup,
  Playing,
  Summary,
}

export interface GameConfig {
  startingScore: number;
  totalLegs: number;
  players: Player[];
}

export interface GameState {
  status: GameStatus;
  currentLeg: number;
  currentPlayerIndex: number;
  legStarterIndex: number;
  turnThrows: Throw[];
  history: Throw[];
  scoreAtStartOfTurn: number;
  finishedPlayerIds: string[]; 
}

