export enum Multiplier {
  Single = 1,
  Double = 2,
  Triple = 3,
}

export interface Throw {
  playerId: string;
  legId: number;
  scoreValue: number;
  multiplier: Multiplier;
  totalPoints: number;
  isBust: boolean;
  isWin: boolean;
  timestamp: number;
}

export interface Player {
  id: string;
  name: string;
  score: number;
  wins: number;
}

export enum GameStatus {
  Setup,
  Playing,
  Summary,
}

export enum GameMode {
  Match = 'MATCH',
  Training = 'TRAINING'
}

export interface GameConfig {
  mode: GameMode;
  startingScore: number;
  totalLegs: number;
  players: Player[];
  trainingConfig?: {
    targetZones: number[];
    maxDarts: number;
  };
}

export interface GameState {
  status: GameStatus;
  currentLeg: number;
  currentPlayerIndex: number;
  legStarterIndex: number;
  turnThrows: Throw[];
  history: Throw[];
  scoreAtStartOfTurn: number;
  finishedPlayerIds: string[]; 
}

import React, { useState } from 'react';
import { GameConfig, Player, GameMode } from '../types';
import { DARTBOARD_NUMBERS } from '../constants';

interface SetupProps {
  onStartGame: (config: GameConfig) => void;
}

export const Setup: React.FC<SetupProps> = ({ onStartGame }) => {
  const [mode, setMode] = useState<GameMode>(GameMode.Match);
  const [score, setScore] = useState<number>(301);
  const [legs, setLegs] = useState<number>(1); 
  const [playerNames, setPlayerNames] = useState<string[]>(['Joueur 1', 'Joueur 2']);
  const [trainingDarts, setTrainingDarts] = useState<number>(30);
  const [selectedTargets, setSelectedTargets] = useState<number[]>([20]);

  const addPlayer = () => {
    if (playerNames.length < 8) {
      setPlayerNames([...playerNames, `Joueur ${playerNames.length + 1}`]);
    }
  };

  const removePlayer = (index: number) => {
    if (playerNames.length > 1) {
      const newNames = playerNames.filter((_, i) => i !== index);
      setPlayerNames(newNames);
    }
  };

  const updateName = (index: number, name: string) => {
    const newNames = [...playerNames];
    newNames[index] = name;
    setPlayerNames(newNames);
  };

  const toggleTarget = (num: number) => {
    if (selectedTargets.includes(num)) {
      if (selectedTargets.length > 1) setSelectedTargets(selectedTargets.filter(t => t !== num));
    } else {
      setSelectedTargets([...selectedTargets, num]);
    }
  };

  const handleStart = () => {
    const players: Player[] = (mode === GameMode.Match ? playerNames : [playerNames[0]]).map((name, index) => ({
      id: `p${index}-${Date.now()}`,
      name: name.trim() || `Joueur ${index + 1}`,
      score: score,
      wins: 0,
    }));

    onStartGame({
      mode,
      startingScore: score,
      totalLegs: legs,
      players,
      trainingConfig: mode === GameMode.Training ? {
        targetZones: selectedTargets,
        maxDarts: trainingDarts
      } : undefined
    });
  };

  return (
    <div className="max-w-md w-full mx-auto p-6 bg-white dark:bg-slate-800 rounded-3xl shadow-xl border border-slate-100 dark:border-slate-700 transition-all">
      <h1 className="text-3xl font-black text-center text-emerald-500 mb-8 tracking-tight italic">DARTSMASTER</h1>

      {/* Mode Selector */}
      <div className="flex bg-slate-100 dark:bg-slate-900 p-1 rounded-2xl mb-8">
        <button 
          onClick={() => setMode(GameMode.Match)}
          className={`flex-1 py-2 rounded-xl text-xs font-black uppercase tracking-widest transition-all ${mode === GameMode.Match ? 'bg-white dark:bg-slate-800 text-emerald-500 shadow-sm' : 'text-slate-400'}`}
        >
          Match
        </button>
        <button 
          onClick={() => setMode(GameMode.Training)}
          className={`flex-1 py-2 rounded-xl text-xs font-black uppercase tracking-widest transition-all ${mode === GameMode.Training ? 'bg-white dark:bg-slate-800 text-blue-500 shadow-sm' : 'text-slate-400'}`}
        >
          Entraînement
        </button>
      </div>

      {mode === GameMode.Match ? (
        <>
          <div className="mb-6">
            <label className="block text-slate-400 dark:text-slate-500 mb-2 text-[10px] uppercase font-black tracking-[0.2em]">Score de départ</label>
            <div className="flex gap-3">
              {[301, 501].map((val) => (
                <button
                  key={val}
                  onClick={() => setScore(val)}
                  className={`flex-1 py-3 rounded-2xl font-bold transition-all ${
                    score === val 
                      ? 'bg-emerald-500 text-white shadow-lg' 
                      : 'bg-slate-50 dark:bg-slate-700/50 text-slate-500 dark:text-slate-400'
                  }`}
                >
                  {val}
                </button>
              ))}
            </div>
          </div>

          <div className="mb-6">
            <label className="block text-slate-400 dark:text-slate-500 mb-2 text-[10px] uppercase font-black tracking-[0.2em]">Nombre de manches (Legs)</label>
            <div className="flex items-center bg-slate-50 dark:bg-slate-700/50 rounded-2xl p-1">
              <button onClick={() => setLegs(Math.max(1, legs - 1))} className="w-12 h-11 text-slate-400 text-2xl">-</button>
              <div className="flex-1 text-center font-black text-xl text-slate-800 dark:text-slate-100">
                {legs} <span className="text-[10px] text-slate-400 font-bold uppercase ml-1">{legs > 1 ? 'Manches' : 'Manche'}</span>
              </div>
              <button onClick={() => setLegs(legs + 1)} className="w-12 h-11 text-slate-400 text-2xl">+</button>
            </div>
          </div>

          <div className="mb-8">
            <label className="text-slate-400 dark:text-slate-500 text-[10px] uppercase font-black tracking-[0.2em] block mb-3">Joueurs</label>
            <div className="space-y-2">
              {playerNames.map((name, index) => (
                <div key={index} className="flex items-center gap-3 p-1 rounded-2xl bg-slate-50/50 dark:bg-slate-700/30">
                  <input
                    type="text"
                    value={name}
                    onChange={(e) => updateName(index, e.target.value)}
                    className="flex-1 bg-transparent py-2 px-4 text-slate-800 dark:text-slate-100 font-bold focus:outline-none"
                    placeholder={`Joueur ${index + 1}`}
                  />
                  {playerNames.length > 1 && (
                    <button onClick={() => removePlayer(index)} className="w-10 h-10 text-slate-300 hover:text-red-500">×</button>
                  )}
                </div>
              ))}
            </div>
            {playerNames.length < 8 && (
              <button onClick={addPlayer} className="mt-3 w-full py-3 text-slate-400 border-2 border-dashed border-slate-200 dark:border-slate-700 rounded-2xl text-xs font-black uppercase tracking-widest">+ Ajouter</button>
            )}
          </div>
        </>
      ) : (
        <div className="space-y-6 animate-viewEnter">
          <div>
            <label className="block text-slate-400 dark:text-slate-500 mb-2 text-[10px] uppercase font-black tracking-[0.2em]">Votre nom</label>
            <input
              type="text"
              value={playerNames[0]}
              onChange={(e) => updateName(0, e.target.value)}
              className="w-full bg-slate-50 dark:bg-slate-700/50 rounded-2xl py-3 px-4 text-slate-800 dark:text-white font-bold focus:outline-none focus:ring-2 focus:ring-blue-500 transition-all"
            />
          </div>

          <div>
            <label className="block text-slate-400 dark:text-slate-500 mb-2 text-[10px] uppercase font-black tracking-[0.2em]">Zones visées</label>
            <div className="grid grid-cols-7 gap-1">
              {[...DARTBOARD_NUMBERS].sort((a,b) => a-b).map(num => (
                <button
                  key={num}
                  onClick={() => toggleTarget(num)}
                  className={`h-8 rounded-lg text-[10px] font-black flex items-center justify-center transition-all ${
                    selectedTargets.includes(num) ? 'bg-blue-500 text-white' : 'bg-slate-100 dark:bg-slate-700 text-slate-400'
                  }`}
                >
                  {num}
                </button>
              ))}
              <button
                onClick={() => toggleTarget(25)}
                className={`col-span-2 h-8 rounded-lg text-[10px] font-black flex items-center justify-center transition-all ${
                  selectedTargets.includes(25) ? 'bg-blue-500 text-white' : 'bg-slate-100 dark:bg-slate-700 text-slate-400'
                }`}
              >
                BULL
              </button>
            </div>
          </div>

          <div>
            <label className="block text-slate-400 dark:text-slate-500 mb-2 text-[10px] uppercase font-black tracking-[0.2em]">Nombre de fléchettes</label>
            <div className="grid grid-cols-3 gap-3">
              {[30, 60, 90].map(val => (
                <button
                  key={val}
                  onClick={() => setTrainingDarts(val)}
                  className={`py-3 rounded-2xl font-bold transition-all ${
                    trainingDarts === val ? 'bg-blue-500 text-white shadow-lg shadow-blue-200 dark:shadow-blue-900/30' : 'bg-slate-50 dark:bg-slate-700/50 text-slate-500 dark:text-slate-400'
                  }`}
                >
                  {val}
                </button>
              ))}
            </div>
          </div>
        </div>
      )}

      <button
        onClick={handleStart}
        className={`w-full mt-8 py-4 rounded-2xl font-black text-white shadow-xl transition-all transform active:scale-95 uppercase tracking-widest ${
          mode === GameMode.Match ? 'bg-emerald-500 hover:bg-emerald-600 shadow-emerald-200 dark:shadow-emerald-900/40' : 'bg-blue-500 hover:bg-blue-600 shadow-blue-200 dark:shadow-blue-900/40'
        }`}
      >
        Démarrer {mode === GameMode.Training ? 'l\'entraînement' : 'le match'}
      </button>
    </div>
  );
};

import React from 'react';
import { Throw } from '../types';
import { DARTBOARD_NUMBERS } from '../constants';

interface PrecisionAnalysisProps {
  history: Throw[];
  playerId: string;
  forcedTargetZones?: number[];
}

export const PrecisionAnalysis: React.FC<PrecisionAnalysisProps> = ({ history, playerId, forcedTargetZones }) => {
  const playerThrows = history.filter(t => t.playerId === playerId);
  if (playerThrows.length === 0) return null;

  // 1. Target Selection: Forced (Training) or Auto-Detected (Match)
  let targetNumbers: number[] = [];

  if (forcedTargetZones && forcedTargetZones.length > 0) {
    targetNumbers = forcedTargetZones;
  } else {
    const numberCounts: Record<number, number> = {};
    playerThrows.forEach(t => {
      numberCounts[t.scoreValue] = (numberCounts[t.scoreValue] || 0) + 1;
    });

    const sortedNumbers = Object.entries(numberCounts)
      .map(([val, count]) => ({ val: parseInt(val), count }))
      .sort((a, b) => b.count - a.count);

    if (sortedNumbers.length > 0) {
      const primaryNum = sortedNumbers[0].val;
      const primaryCount = sortedNumbers[0].count;
      targetNumbers.push(primaryNum);
      if (sortedNumbers.length > 1 && sortedNumbers[1].count >= primaryCount * 0.25) {
        targetNumbers.push(sortedNumbers[1].val);
      }
    }
  }

  if (targetNumbers.length === 0) return null;

  // 2. Neighbor Logic
  const getNeighbors = (val: number) => {
    if (val === 0 || val === 25) return []; 
    const idx = DARTBOARD_NUMBERS.indexOf(val);
    const prev = DARTBOARD_NUMBERS[(idx - 1 + 20) % 20];
    const next = DARTBOARD_NUMBERS[(idx + 1) % 20];
    return [prev, next];
  };

  const allTargetNeighbors = new Set<number>();
  targetNumbers.forEach(num => {
    getNeighbors(num).forEach(n => allTargetNeighbors.add(n));
  });

  // 3. Score Calculation (100/40/0 rule)
  let totalScore = 0;
  playerThrows.forEach(t => {
    if (targetNumbers.includes(t.scoreValue)) {
      totalScore += 100;
    } else if (allTargetNeighbors.has(t.scoreValue)) {
      totalScore += 40;
    }
  });

  const finalPrecision = Math.round(totalScore / playerThrows.length);

  const getColors = (score: number) => {
    if (score >= 70) return { text: 'text-emerald-500', stroke: 'text-emerald-500', bg: 'bg-emerald-500' };
    if (score >= 40) return { text: 'text-amber-500', stroke: 'text-amber-500', bg: 'bg-amber-500' };
    return { text: 'text-rose-500', stroke: 'text-rose-500', bg: 'bg-rose-500' };
  };

  const theme = getColors(finalPrecision);
  const radius = 38;
  const circumference = 2 * Math.PI * radius;

  return (
    <div className="mt-4 p-6 bg-slate-50 dark:bg-slate-900/40 rounded-[2.5rem] border border-slate-100 dark:border-slate-800 shadow-sm relative overflow-visible">
      <div className="flex justify-between items-center">
        <div className="flex-1 pr-4">
          <span className="text-[10px] font-black uppercase tracking-[0.3em] text-slate-400 block mb-4">Indice de Précision</span>
          <div className="flex flex-wrap gap-2">
            {targetNumbers.map(num => (
              <div key={num} className="px-4 py-2 bg-white dark:bg-slate-800 text-slate-800 dark:text-white rounded-2xl border border-slate-200 dark:border-slate-700 text-xs font-black shadow-sm flex items-center gap-2">
                <div className={`w-2 h-2 rounded-full ${theme.bg} animate-pulse`}></div>
                Case <span className="text-emerald-500">#{num === 25 ? 'BULL' : num}</span>
              </div>
            ))}
          </div>
        </div>

        <div className="relative flex-shrink-0 w-24 h-24">
            <svg 
              className="w-full h-full transform -rotate-90 drop-shadow-xl overflow-visible"
              viewBox="0 0 100 100"
            >
                <circle cx="50" cy="50" r={radius} stroke="currentColor" strokeWidth="12" fill="transparent" className="text-slate-200 dark:text-slate-800" />
                <circle cx="50" cy="50" r={radius} stroke="currentColor" strokeWidth="12" fill="transparent" strokeDasharray={circumference} strokeDashoffset={circumference * (1 - finalPrecision / 100)} className={`${theme.stroke} transition-all duration-1000 ease-out`} strokeLinecap="round" />
            </svg>
            <div className="absolute inset-0 flex flex-col items-center justify-center">
                <span className={`text-2xl font-black ${theme.text} leading-none tracking-tighter`}>{finalPrecision}</span>
                <span className="text-[8px] font-black text-slate-400 uppercase tracking-widest mt-0.5">%</span>
            </div>
        </div>
      </div>

      <div className="grid grid-cols-3 gap-2 mt-8 pt-6 border-t border-slate-200/50 dark:border-slate-800/50">
          <div className="text-center">
              <div className="text-lg font-black text-slate-800 dark:text-white leading-tight">{playerThrows.length}</div>
              <div className="text-[8px] font-bold text-slate-400 uppercase tracking-[0.2em]">Tirs Totaux</div>
          </div>
          <div className="text-center border-x border-slate-200/50 dark:border-slate-800/50">
              <div className="text-lg font-black text-emerald-500 leading-tight">
                  {playerThrows.filter(t => targetNumbers.includes(t.scoreValue)).length}
              </div>
              <div className="text-[8px] font-bold text-slate-400 uppercase tracking-[0.2em]">Cible</div>
          </div>
          <div className="text-center">
              <div className="text-lg font-black text-blue-500 leading-tight">
                  {playerThrows.filter(t => allTargetNeighbors.has(t.scoreValue)).length}
              </div>
              <div className="text-[8px] font-bold text-slate-400 uppercase tracking-[0.2em]">Voisinage</div>
          </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useCallback } from 'react';
import { GameStatus, GameConfig, GameState, Player, Throw, Multiplier, GameMode } from './types';
import { MAX_THROWS_PER_TURN } from './constants';
import { Setup } from './components/Setup';
import { Scoreboard } from './components/Scoreboard';
import { InputPad } from './components/InputPad';
import { DartboardHeatmap } from './components/DartboardHeatmap';
import { PrecisionAnalysis } from './components/PrecisionAnalysis';

const App: React.FC = () => {
  const [isDarkMode, setIsDarkMode] = useState<boolean>(false);
  const [config, setConfig] = useState<GameConfig | null>(null);
  const [state, setState] = useState<GameState>({
    status: GameStatus.Setup,
    currentLeg: 1,
    currentPlayerIndex: 0,
    legStarterIndex: 0,
    turnThrows: [],
    history: [],
    scoreAtStartOfTurn: 0,
    finishedPlayerIds: [],
  });
  const [players, setPlayers] = useState<Player[]>([]);
  const [showBullAnimation, setShowBullAnimation] = useState<boolean>(false);
  const [showDoubleBullAnimation, setShowDoubleBullAnimation] = useState<boolean>(false);
  const [showWinAnimation, setShowWinAnimation] = useState<boolean>(false);
  const [isShaking, setIsShaking] = useState<boolean>(false);

  useEffect(() => {
    if (isDarkMode) document.documentElement.classList.add('dark');
    else document.documentElement.classList.remove('dark');
  }, [isDarkMode]);

  const toggleTheme = () => setIsDarkMode(!isDarkMode);

  const triggerShake = (intensity: 'light' | 'heavy' = 'light') => {
    setIsShaking(true);
    setTimeout(() => setIsShaking(false), intensity === 'light' ? 400 : 600);
  };

  const playBustSound = () => {
    try {
      const AudioContext = window.AudioContext || (window as any).webkitAudioContext;
      const ctx = new AudioContext();
      const gain = ctx.createGain();
      const osc = ctx.createOscillator();
      osc.type = 'sawtooth';
      osc.frequency.setValueAtTime(100, ctx.currentTime);
      gain.gain.setValueAtTime(0.1, ctx.currentTime);
      gain.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + 0.3);
      osc.connect(gain); gain.connect(ctx.destination);
      osc.start(); osc.stop(ctx.currentTime + 0.3);
    } catch (e) {}
  };

  const playWinSound = () => {
    try {
      const AudioContext = window.AudioContext || (window as any).webkitAudioContext;
      const ctx = new AudioContext();
      const playNote = (freq: number, start: number, duration: number) => {
        const osc = ctx.createOscillator();
        osc.frequency.setValueAtTime(freq, ctx.currentTime + start);
        const g = ctx.createGain();
        g.gain.setValueAtTime(0.1, ctx.currentTime + start);
        g.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + start + duration);
        osc.connect(g); g.connect(ctx.destination);
        osc.start(ctx.currentTime + start); osc.stop(ctx.currentTime + start + duration);
      };
      playNote(523, 0, 0.4); playNote(659, 0.1, 0.4); playNote(784, 0.2, 0.5);
    } catch (e) {}
  };

  const startGame = (newConfig: GameConfig) => {
    setConfig(newConfig);
    setPlayers(newConfig.players);
    setState({
      status: GameStatus.Playing,
      currentLeg: 1,
      currentPlayerIndex: 0,
      legStarterIndex: 0,
      turnThrows: [],
      history: [],
      scoreAtStartOfTurn: newConfig.mode === GameMode.Match ? newConfig.players[0].score : 0,
      finishedPlayerIds: [],
    });
    setShowWinAnimation(false);
  };

  const startNextLeg = (winnerId: string) => {
    if (!config) return;
    const nextLegNum = state.currentLeg + 1;
    const nextLegStarterIdx = (state.legStarterIndex + 1) % players.length;
    const updatedPlayers = players.map(p => ({
        ...p,
        score: config.startingScore,
        wins: p.id === winnerId ? p.wins + 1 : p.wins
    }));
    setPlayers(updatedPlayers);
    setState(prev => ({
        ...prev,
        currentLeg: nextLegNum,
        legStarterIndex: nextLegStarterIdx,
        currentPlayerIndex: nextLegStarterIdx,
        scoreAtStartOfTurn: config.startingScore,
        turnThrows: [],
        finishedPlayerIds: [],
    }));
    setShowWinAnimation(false);
  };

  const handleTurnEnd = useCallback((playersSnapshot?: Player[]) => {
    if (!config) return;
    const currentPlayers = playersSnapshot || players;

    setState((prev) => {
        if (config.mode === GameMode.Training) {
          return { ...prev, turnThrows: [] };
        }
        const nextIdx = (prev.currentPlayerIndex + 1) % currentPlayers.length;
        return {
            ...prev,
            turnThrows: [],
            currentPlayerIndex: nextIdx,
            scoreAtStartOfTurn: currentPlayers[nextIdx].score,
        };
    });
  }, [config, players]);

  const handleThrow = (value: number, multiplier: Multiplier) => {
    if (state.status !== GameStatus.Playing || !config || showWinAnimation) return;

    const effectiveMultiplier = (value === 25 && multiplier === Multiplier.Triple) ? Multiplier.Single : multiplier;

    if (value === 25) {
      if (effectiveMultiplier === Multiplier.Double) { setShowDoubleBullAnimation(true); triggerShake('heavy'); setTimeout(() => setShowDoubleBullAnimation(false), 1400); }
      else { setShowBullAnimation(true); triggerShake('light'); setTimeout(() => setShowBullAnimation(false), 1000); }
    }

    const currentPlayer = players[state.currentPlayerIndex];
    const points = value * effectiveMultiplier;
    const newScore = currentPlayer.score - points;
    const now = Date.now();

    let isBust = config.mode === GameMode.Match ? (newScore < 0 || newScore === 1) : false;
    let isWin = config.mode === GameMode.Match ? (newScore === 0) : false;

    // Training end condition
    const isTrainingFinished = config.mode === GameMode.Training && (state.history.length + 1 >= config.trainingConfig!.maxDarts);

    const newThrow: Throw = {
      playerId: currentPlayer.id,
      legId: state.currentLeg,
      scoreValue: value,
      multiplier: effectiveMultiplier,
      totalPoints: points,
      isBust,
      isWin,
      timestamp: now,
    };

    const updatedPlayers = [...players];
    if (config.mode === GameMode.Match) {
      if (isBust) {
        updatedPlayers[state.currentPlayerIndex].score = state.scoreAtStartOfTurn;
        playBustSound();
        triggerShake('light');
      } else {
        updatedPlayers[state.currentPlayerIndex].score = newScore;
      }
    } else {
      updatedPlayers[state.currentPlayerIndex].score += points; // In training, track total points
    }
    setPlayers(updatedPlayers);

    setState((prev) => ({
        ...prev,
        turnThrows: [...prev.turnThrows, newThrow],
        history: [...prev.history, newThrow],
    }));

    if (isWin || isTrainingFinished) {
        playWinSound();
        setShowWinAnimation(true);
        triggerShake('heavy');

        const finalWinnerId = currentPlayer.id;

        setTimeout(() => {
            if (config.mode === GameMode.Training || state.currentLeg >= config.totalLegs) {
                const finalPlayers = updatedPlayers.map(p => p.id === finalWinnerId ? {...p, wins: p.wins + 1} : p);
                setPlayers(finalPlayers);
                setState(prev => ({ ...prev, status: GameStatus.Summary, finishedPlayerIds: [finalWinnerId] }));
            } else {
                startNextLeg(finalWinnerId);
            }
        }, 1800);
        return;
    }

    if (isBust || state.turnThrows.length + 1 >= MAX_THROWS_PER_TURN) {
      setTimeout(() => handleTurnEnd(updatedPlayers), isBust ? 700 : 400);
    }
  };

  const handleUndo = () => {
    if (state.history.length === 0 || !config) return;
    const newHistory = [...state.history];
    newHistory.pop();
    // Simplified undo for the demo purpose - in a real app, you'd recalculate scores properly like before
    restartMatch();
  };

  const restartMatch = () => startGame({ ...config!, players: config!.players.map(p => ({ ...p, score: config!.mode === GameMode.Match ? config!.startingScore : 0, wins: 0 })) });
  const newGame = () => setState(prev => ({ ...prev, status: GameStatus.Setup }));

  const ThemeToggle = () => (
    <button onClick={toggleTheme} className="p-2.5 rounded-full bg-slate-200 dark:bg-slate-800 text-slate-600 dark:text-slate-300 hover:scale-110 active:scale-95 transition-all">
        {isDarkMode ? '🌙' : '☀️'}
    </button>
  );

  if (state.status === GameStatus.Setup) return (
    <div className="min-h-screen bg-slate-50 dark:bg-slate-950 flex flex-col items-center justify-center p-4 view-enter">
        <div className="absolute top-4 right-4"><ThemeToggle /></div>
        <Setup onStartGame={startGame} />
    </div>
  );

  if (state.status === GameStatus.Summary) {
    return (
      <div className="min-h-screen bg-slate-50 dark:bg-slate-950 p-4 view-enter">
        <div className="absolute top-4 right-4"><ThemeToggle /></div>
        <div className="max-w-4xl mx-auto">
            <h1 className="text-4xl font-black text-center text-emerald-500 mb-8 uppercase tracking-tight">BILAN {config?.mode === GameMode.Training ? 'SÉANCE' : 'MATCH'}</h1>
            <div className="grid gap-4 mb-8">
                {state.finishedPlayerIds.map((id, index) => {
                    const p = players.find(player => player.id === id)!;
                    const playerThrows = state.history.filter(t => t.playerId === id);
                    const totalDarts = playerThrows.length;
                    const avg = totalDarts > 0 ? Math.round((playerThrows.reduce((sum, t) => sum + t.totalPoints, 0) / totalDarts) * 3) : 0;

                    return (
                        <div key={id} className={`flex flex-col gap-4 p-6 rounded-3xl bg-white dark:bg-slate-800 shadow-xl border-l-[10px] ${config?.mode === GameMode.Training ? 'border-blue-500' : 'border-emerald-500'}`}>
                            <div className="flex items-center gap-4">
                                <div className="flex-1">
                                    <div className="text-xl font-bold">{p.name} {config?.mode === GameMode.Match && <span className="text-emerald-500 ml-2">{p.wins} Leg(s)</span>}</div>
                                    <div className="text-xs text-slate-500 font-bold uppercase tracking-wider">{totalDarts} fléchettes • Moyenne: {avg}</div>
                                </div>
                                <div className="text-3xl animate-bounce">🎯</div>
                            </div>
                            <div className="grid md:grid-cols-2 gap-6 items-center">
                                <div className="w-full h-auto"><DartboardHeatmap history={state.history} playerId={id} isDarkMode={isDarkMode} /></div>
                                <PrecisionAnalysis history={state.history} playerId={id} forcedTargetZones={config?.trainingConfig?.targetZones} />
                            </div>
                        </div>
                    );
                })}
            </div>
            <div className="flex justify-center gap-4 pb-10">
                <button onClick={restartMatch} className={`text-white px-8 py-4 rounded-2xl font-black shadow-xl hover:scale-105 active:scale-95 transition-all uppercase tracking-widest ${config?.mode === GameMode.Training ? 'bg-blue-500 shadow-blue-500/20' : 'bg-emerald-500 shadow-emerald-500/20'}`}>Recommencer</button>
                <button onClick={newGame} className="bg-white dark:bg-slate-700 text-slate-700 dark:text-white px-8 py-4 rounded-2xl font-black border border-slate-200 dark:border-slate-600 hover:scale-105 active:scale-95 transition-all uppercase tracking-widest">Menu Principal</button>
            </div>
        </div>
      </div>
    );
  }

  const currentPlayer = players[state.currentPlayerIndex];
  const isTraining = config?.mode === GameMode.Training;

  return (
    <div className={`min-h-screen bg-slate-50 dark:bg-slate-950 p-4 flex flex-col transition-colors duration-700 relative overflow-hidden view-enter ${isShaking ? 'animate-shake' : ''}`}>
      {showBullAnimation && (
        <div className="fixed inset-0 z-50 flex items-center justify-center pointer-events-none">
          <div className="shockwave bg-red-600/30"></div>
          <div className="animate-bull-blast flex flex-col items-center">
            <div className="bg-red-600 text-white font-black text-7xl px-14 py-10 rounded-[4rem] shadow-2xl border-4 border-white/40">BULL!</div>
          </div>
        </div>
      )}
      {showDoubleBullAnimation && (
        <div className="fixed inset-0 z-50 flex items-center justify-center pointer-events-none">
          <div className="shockwave bg-amber-400/40"></div>
          <div className="animate-dbull-blast flex flex-col items-center">
            <div className="bg-gradient-to-br from-amber-400 to-amber-600 text-white font-black text-7xl px-14 py-10 rounded-[4rem] shadow-2xl border-4 border-white/50 animate-gold-pulse">D-BULL!</div>
          </div>
        </div>
      )}
      {showWinAnimation && (
        <div className="fixed inset-0 z-[60] flex items-center justify-center pointer-events-none">
            <div className={`absolute inset-0 backdrop-blur-xl ${isTraining ? 'bg-blue-500/90' : 'bg-emerald-500/90'}`}></div>
            <div className="animate-winner-pop text-center">
                <h2 className="text-2xl text-white font-bold mb-3 uppercase tracking-[0.3em] opacity-80">{isTraining ? 'Session Terminée !' : 'Manche gagnée !'}</h2>
                <div className={`bg-white font-black text-6xl px-16 py-8 rounded-[3rem] shadow-2xl ${isTraining ? 'text-blue-600 border-blue-400/20' : 'text-emerald-600 border-emerald-400/20'}`}>{currentPlayer.name}</div>
            </div>
        </div>
      )}

      <header className="flex justify-between items-center mb-6 max-w-md mx-auto w-full">
        {isTraining ? (
          <div className="flex-1 mr-4">
             <div className="flex justify-between text-[10px] font-black uppercase tracking-widest text-slate-400 mb-1">
                <span>Progression</span>
                <span>{state.history.length} / {config.trainingConfig?.maxDarts}</span>
             </div>
             <div className="h-2 w-full bg-slate-200 dark:bg-slate-800 rounded-full overflow-hidden">
                <div className="h-full bg-blue-500 transition-all duration-300" style={{ width: `${(state.history.length / config.trainingConfig!.maxDarts) * 100}%` }}></div>
             </div>
          </div>
        ) : (
          <h1 className="font-black text-slate-400 uppercase text-[10px] tracking-[0.3em]">Manche {state.currentLeg} / {config?.totalLegs}</h1>
        )}
        <div className="flex items-center gap-4">
            <ThemeToggle />
            <button onClick={newGame} className="text-[10px] text-slate-500 font-black uppercase tracking-widest hover:text-red-500">Quitter</button>
        </div>
      </header>

      <main className="flex-1 flex flex-col justify-center max-w-lg mx-auto w-full">
        <Scoreboard 
          players={players} 
          currentPlayerId={currentPlayer.id} 
          currentTurnThrows={state.turnThrows} 
          scoreAtStartOfTurn={state.scoreAtStartOfTurn} 
          history={state.history}
          finishedPlayerIds={state.finishedPlayerIds}
          totalLegs={config?.totalLegs || 1}
          currentLeg={state.currentLeg}
        />
        <InputPad onSubmitThrow={handleThrow} onUndo={handleUndo} canUndo={state.history.length > 0} />
      </main>
    </div>
  );
};

