import React, { useState, useEffect, useCallback } from 'react';
import { GameStatus, GameConfig, GameState, Player, Throw, Multiplier, GameMode } from './types';
import { MAX_THROWS_PER_TURN } from './constants';
import { Setup } from './components/Setup';
import { Scoreboard } from './components/Scoreboard';
import { InputPad } from './components/InputPad';
import { DartboardHeatmap } from './components/DartboardHeatmap';
import { PrecisionAnalysis } from './components/PrecisionAnalysis';

const App: React.FC = () => {
  const [isDarkMode, setIsDarkMode] = useState<boolean>(false);
  const [config, setConfig] = useState<GameConfig | null>(null);
  const [state, setState] = useState<GameState>({
    status: GameStatus.Setup,
    currentLeg: 1,
    currentPlayerIndex: 0,
    legStarterIndex: 0,
    turnThrows: [],
    history: [],
    scoreAtStartOfTurn: 0,
    finishedPlayerIds: [],
  });
  const [players, setPlayers] = useState<Player[]>([]);
  const [showBullAnimation, setShowBullAnimation] = useState<boolean>(false);
  const [showDoubleBullAnimation, setShowDoubleBullAnimation] = useState<boolean>(false);
  const [showWinAnimation, setShowWinAnimation] = useState<boolean>(false);
  const [isShaking, setIsShaking] = useState<boolean>(false);

  useEffect(() => {
    if (isDarkMode) document.documentElement.classList.add('dark');
    else document.documentElement.classList.remove('dark');
  }, [isDarkMode]);

  const toggleTheme = () => setIsDarkMode(!isDarkMode);

  const triggerShake = (intensity: 'light' | 'heavy' = 'light') => {
    setIsShaking(true);
    setTimeout(() => setIsShaking(false), intensity === 'light' ? 400 : 600);
  };

  const playBustSound = () => {
    try {
      const AudioContext = window.AudioContext || (window as any).webkitAudioContext;
      const ctx = new AudioContext();
      const gain = ctx.createGain();
      const osc = ctx.createOscillator();
      osc.type = 'sawtooth';
      osc.frequency.setValueAtTime(100, ctx.currentTime);
      gain.gain.setValueAtTime(0.1, ctx.currentTime);
      gain.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + 0.3);
      osc.connect(gain); gain.connect(ctx.destination);
      osc.start(); osc.stop(ctx.currentTime + 0.3);
    } catch (e) {}
  };

  const playWinSound = () => {
    try {
      const AudioContext = window.AudioContext || (window as any).webkitAudioContext;
      const ctx = new AudioContext();
      const playNote = (freq: number, start: number, duration: number) => {
        const osc = ctx.createOscillator();
        osc.frequency.setValueAtTime(freq, ctx.currentTime + start);
        const g = ctx.createGain();
        g.gain.setValueAtTime(0.1, ctx.currentTime + start);
        g.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + start + duration);
        osc.connect(g); g.connect(ctx.destination);
        osc.start(ctx.currentTime + start); osc.stop(ctx.currentTime + start + duration);
      };
      playNote(523, 0, 0.4); playNote(659, 0.1, 0.4); playNote(784, 0.2, 0.5);
    } catch (e) {}
  };

  const startGame = (newConfig: GameConfig) => {
    setConfig(newConfig);
    setPlayers(newConfig.players);
    setState({
      status: GameStatus.Playing,
      currentLeg: 1,
      currentPlayerIndex: 0,
      legStarterIndex: 0,
      turnThrows: [],
      history: [],
      scoreAtStartOfTurn: newConfig.mode === GameMode.Match ? newConfig.players[0].score : 0,
      finishedPlayerIds: [],
    });
    setShowWinAnimation(false);
  };

  const startNextLeg = (winnerId: string) => {
    if (!config) return;
    const nextLegNum = state.currentLeg + 1;
    const nextLegStarterIdx = (state.legStarterIndex + 1) % players.length;
    const updatedPlayers = players.map(p => ({
        ...p,
        score: config.startingScore,
        wins: p.id === winnerId ? p.wins + 1 : p.wins
    }));
    setPlayers(updatedPlayers);
    setState(prev => ({
        ...prev,
        currentLeg: nextLegNum,
        legStarterIndex: nextLegStarterIdx,
        currentPlayerIndex: nextLegStarterIdx,
        scoreAtStartOfTurn: config.startingScore,
        turnThrows: [],
        finishedPlayerIds: [],
    }));
    setShowWinAnimation(false);
  };

  const handleTurnEnd = useCallback((playersSnapshot?: Player[]) => {
    if (!config) return;
    const currentPlayers = playersSnapshot || players;

    setState((prev) => {
        if (config.mode === GameMode.Training) {
          return { ...prev, turnThrows: [] };
        }
        const nextIdx = (prev.currentPlayerIndex + 1) % currentPlayers.length;
        return {
            ...prev,
            turnThrows: [],
            currentPlayerIndex: nextIdx,
            scoreAtStartOfTurn: currentPlayers[nextIdx].score,
        };
    });
  }, [config, players]);

  const handleThrow = (value: number, multiplier: Multiplier) => {
    if (state.status !== GameStatus.Playing || !config || showWinAnimation) return;

    const effectiveMultiplier = (value === 25 && multiplier === Multiplier.Triple) ? Multiplier.Single : multiplier;

    if (value === 25) {
      if (effectiveMultiplier === Multiplier.Double) { setShowDoubleBullAnimation(true); triggerShake('heavy'); setTimeout(() => setShowDoubleBullAnimation(false), 1400); }
      else { setShowBullAnimation(true); triggerShake('light'); setTimeout(() => setShowBullAnimation(false), 1000); }
    }

    const currentPlayer = players[state.currentPlayerIndex];
    const points = value * effectiveMultiplier;
    const newScore = currentPlayer.score - points;
    const now = Date.now();

    let isBust = config.mode === GameMode.Match ? (newScore < 0 || newScore === 1) : false;
    let isWin = config.mode === GameMode.Match ? (newScore === 0) : false;

    // Training end condition
    const isTrainingFinished = config.mode === GameMode.Training && (state.history.length + 1 >= config.trainingConfig!.maxDarts);

    const newThrow: Throw = {
      playerId: currentPlayer.id,
      legId: state.currentLeg,
      scoreValue: value,
      multiplier: effectiveMultiplier,
      totalPoints: points,
      isBust,
      isWin,
      timestamp: now,
    };

    const updatedPlayers = [...players];
    if (config.mode === GameMode.Match) {
      if (isBust) {
        updatedPlayers[state.currentPlayerIndex].score = state.scoreAtStartOfTurn;
        playBustSound();
        triggerShake('light');
      } else {
        updatedPlayers[state.currentPlayerIndex].score = newScore;
      }
    } else {
      updatedPlayers[state.currentPlayerIndex].score += points; // In training, track total points
    }
    setPlayers(updatedPlayers);

    setState((prev) => ({
        ...prev,
        turnThrows: [...prev.turnThrows, newThrow],
        history: [...prev.history, newThrow],
    }));

    if (isWin || isTrainingFinished) {
        playWinSound();
        setShowWinAnimation(true);
        triggerShake('heavy');

        const finalWinnerId = currentPlayer.id;

        setTimeout(() => {
            if (config.mode === GameMode.Training || state.currentLeg >= config.totalLegs) {
                const finalPlayers = updatedPlayers.map(p => p.id === finalWinnerId ? {...p, wins: p.wins + 1} : p);
                setPlayers(finalPlayers);
                setState(prev => ({ ...prev, status: GameStatus.Summary, finishedPlayerIds: [finalWinnerId] }));
            } else {
                startNextLeg(finalWinnerId);
            }
        }, 1800);
        return;
    }

    if (isBust || state.turnThrows.length + 1 >= MAX_THROWS_PER_TURN) {
      setTimeout(() => handleTurnEnd(updatedPlayers), isBust ? 700 : 400);
    }
  };

  const handleUndo = () => {
    if (state.history.length === 0 || !config) return;
    const newHistory = [...state.history];
    newHistory.pop();
    // Simplified undo for the demo purpose - in a real app, you'd recalculate scores properly
    restartMatch();
  };

  const restartMatch = () => startGame({ ...config!, players: config!.players.map(p => ({ ...p, score: config!.mode === GameMode.Match ? config!.startingScore : 0, wins: 0 })) });
  const newGame = () => setState(prev => ({ ...prev, status: GameStatus.Setup }));

  const ThemeToggle = () => (
    <button onClick={toggleTheme} className="p-2.5 rounded-full bg-slate-200 dark:bg-slate-800 text-slate-600 dark:text-slate-300 hover:scale-110 active:scale-95 transition-all">
        {isDarkMode ? '🌙' : '☀️'}
    </button>
  );

  if (state.status === GameStatus.Setup) return (
    <div className="min-h-screen bg-slate-50 dark:bg-slate-950 flex flex-col items-center justify-center p-4 overflow-y-auto view-enter">
        <div className="absolute top-4 right-4 z-10"><ThemeToggle /></div>
        <div className="py-8 w-full">
          <Setup onStartGame={startGame} />
        </div>
    </div>
  );

  if (state.status === GameStatus.Summary) {
    return (
      <div className="min-h-screen bg-slate-50 dark:bg-slate-950 p-4 overflow-y-auto view-enter">
        <div className="sticky top-0 z-10 flex justify-end p-2 bg-slate-50/80 dark:bg-slate-950/80 backdrop-blur-md -mx-4 mb-4">
          <ThemeToggle />
        </div>
        <div className="max-w-5xl mx-auto w-full">
            <h1 className="text-3xl sm:text-4xl font-black text-center text-emerald-500 mb-8 uppercase tracking-tight">BILAN {config?.mode === GameMode.Training ? 'SÉANCE' : 'MATCH'}</h1>
            <div className="grid gap-6 mb-8">
                {state.finishedPlayerIds.map((id) => {
                    const p = players.find(player => player.id === id)!;
                    const playerThrows = state.history.filter(t => t.playerId === id);
                    const totalDarts = playerThrows.length;
                    const totalPoints = playerThrows.reduce((sum, t) => sum + t.totalPoints, 0);
                    const avg = totalDarts > 0 ? Math.round((totalPoints / totalDarts) * 3) : 0;

                    return (
                        <div key={id} className={`flex flex-col gap-6 p-4 sm:p-8 rounded-[2rem] sm:rounded-[3rem] bg-white dark:bg-slate-800 shadow-xl border-l-[8px] sm:border-l-[12px] ${config?.mode === GameMode.Training ? 'border-blue-500' : 'border-emerald-500'}`}>
                            <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4">
                                <div>
                                    <div className="text-2xl font-black text-slate-800 dark:text-white leading-tight">{p.name} {config?.mode === GameMode.Match && <span className="text-emerald-500 ml-2">{p.wins} Leg(s)</span>}</div>
                                    <div className="text-[10px] text-slate-400 font-black uppercase tracking-[0.2em] mt-1">{totalDarts} fléchettes • Moyenne: {avg}</div>
                                </div>
                                <div className="text-4xl sm:text-5xl animate-bounce hidden sm:block">🎯</div>
                            </div>
                            <div className="grid lg:grid-cols-2 gap-8 items-start">
                                <div className="w-full flex justify-center bg-slate-50 dark:bg-slate-900/40 p-4 rounded-3xl"><DartboardHeatmap history={state.history} playerId={id} isDarkMode={isDarkMode} /></div>
                                <PrecisionAnalysis history={state.history} playerId={id} forcedTargetZones={config?.trainingConfig?.targetZones} />
                            </div>
                        </div>
                    );
                })}
            </div>
            <div className="flex flex-col sm:flex-row justify-center gap-4 pb-12 px-4">
                <button onClick={restartMatch} className={`w-full sm:w-auto text-white px-10 py-5 rounded-2xl font-black shadow-xl hover:scale-105 active:scale-95 transition-all uppercase tracking-widest ${config?.mode === GameMode.Training ? 'bg-blue-500 shadow-blue-500/20' : 'bg-emerald-500 shadow-emerald-500/20'}`}>Recommencer</button>
                <button onClick={newGame} className="w-full sm:w-auto bg-white dark:bg-slate-700 text-slate-700 dark:text-white px-10 py-5 rounded-2xl font-black border border-slate-200 dark:border-slate-600 hover:scale-105 active:scale-95 transition-all uppercase tracking-widest">Menu Principal</button>
            </div>
        </div>
      </div>
    );
  }

  const currentPlayer = players[state.currentPlayerIndex];
  const isTraining = config?.mode === GameMode.Training;

  return (
    <div className={`min-h-screen bg-slate-50 dark:bg-slate-950 p-4 sm:p-6 flex flex-col transition-colors duration-700 relative overflow-x-hidden overflow-y-auto view-enter ${isShaking ? 'animate-shake' : ''}`}>
      {showBullAnimation && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center pointer-events-none p-4">
          <div className="shockwave bg-red-600/30"></div>
          <div className="animate-bull-blast flex flex-col items-center">
            <div className="bg-red-600 text-white font-black text-5xl sm:text-7xl px-8 sm:px-14 py-6 sm:py-10 rounded-[3rem] sm:rounded-[4rem] shadow-2xl border-4 border-white/40">BULL!</div>
          </div>
        </div>
      )}
      {showDoubleBullAnimation && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center pointer-events-none p-4">
          <div className="shockwave bg-amber-400/40"></div>
          <div className="animate-dbull-blast flex flex-col items-center">
            <div className="bg-gradient-to-br from-amber-400 to-amber-600 text-white font-black text-5xl sm:text-7xl px-8 sm:px-14 py-6 sm:py-10 rounded-[3rem] sm:rounded-[4rem] shadow-2xl border-4 border-white/50 animate-gold-pulse">D-BULL!</div>
          </div>
        </div>
      )}
      {showWinAnimation && (
        <div className="fixed inset-0 z-[110] flex items-center justify-center pointer-events-none p-4">
            <div className={`absolute inset-0 backdrop-blur-xl ${isTraining ? 'bg-blue-500/90' : 'bg-emerald-500/90'}`}></div>
            <div className="animate-winner-pop text-center">
                <h2 className="text-xl sm:text-2xl text-white font-bold mb-3 uppercase tracking-[0.3em] opacity-80">{isTraining ? 'Session Terminée !' : 'Manche gagnée !'}</h2>
                <div className={`bg-white font-black text-4xl sm:text-6xl px-10 sm:px-16 py-6 sm:py-8 rounded-[2rem] sm:rounded-[3rem] shadow-2xl ${isTraining ? 'text-blue-600 border-blue-400/20' : 'text-emerald-600 border-emerald-400/20'}`}>{currentPlayer.name}</div>
            </div>
        </div>
      )}

      <header className="flex justify-between items-center mb-6 max-w-lg mx-auto w-full sticky top-0 z-20 bg-slate-50/80 dark:bg-slate-950/80 backdrop-blur-md p-2 rounded-2xl">
        {isTraining ? (
          <div className="flex-1 mr-4">
             <div className="flex justify-between text-[10px] font-black uppercase tracking-widest text-slate-400 mb-1.5">
                <span>Séance Training</span>
                <span>{state.history.length} / {config.trainingConfig?.maxDarts}</span>
             </div>
             <div className="h-2.5 w-full bg-slate-200 dark:bg-slate-800 rounded-full overflow-hidden shadow-inner">
                <div className="h-full bg-blue-500 transition-all duration-300 shadow-[0_0_8px_rgba(59,130,246,0.5)]" style={{ width: `${Math.min(100, (state.history.length / config.trainingConfig!.maxDarts) * 100)}%` }}></div>
             </div>
          </div>
        ) : (
          <h1 className="font-black text-slate-400 uppercase text-[10px] tracking-[0.3em] bg-slate-200/50 dark:bg-slate-800/50 px-4 py-2 rounded-full">Leg {state.currentLeg} / {config?.totalLegs}</h1>
        )}
        <div className="flex items-center gap-3">
            <ThemeToggle />
            <button onClick={newGame} className="text-[10px] text-white bg-rose-500 px-3 py-2 rounded-xl font-black uppercase tracking-widest shadow-md shadow-rose-200 dark:shadow-rose-900/20 hover:scale-105 active:scale-95 transition-all">Quitter</button>
        </div>
      </header>

      <main className="flex-1 flex flex-col justify-start lg:justify-center max-w-lg mx-auto w-full py-4 gap-4">
        <Scoreboard 
          players={players} 
          currentPlayerId={currentPlayer.id} 
          currentTurnThrows={state.turnThrows} 
          scoreAtStartOfTurn={state.scoreAtStartOfTurn} 
          history={state.history}
          finishedPlayerIds={state.finishedPlayerIds}
          totalLegs={config?.totalLegs || 1}
          currentLeg={state.currentLeg}
        />
        <div className="mt-auto sm:mt-0">
          <InputPad onSubmitThrow={handleThrow} onUndo={handleUndo} canUndo={state.history.length > 0} />
        </div>
      </main>
    </div>
  );
};

