            <div className="animate-viewEnter">
              <label className="block text-slate-400 dark:text-slate-500 mb-3 text-[9px] uppercase font-black tracking-[0.2em]">Score de départ</label>
              <div className="flex gap-4">
                {[301, 501].map((val) => (
                  <button
                    key={val}
                    onClick={() => setScore(val)}
                    className={`flex-1 py-4 rounded-2xl font-black text-lg transition-all ${
                      score === val 
                        ? 'bg-emerald-500 text-white shadow-lg shadow-emerald-200 dark:shadow-emerald-900/30' 
                        : 'bg-slate-50 dark:bg-slate-700/50 text-slate-500 dark:text-slate-400 hover:bg-slate-100 dark:hover:bg-slate-700'
                    }`}
                  >
                    {val}
                  </button>
                ))}
              </div>
            </div>

            <div className="animate-viewEnter" style={{animationDelay: '0.1s'}}>
