    <path d="M22.5,1.5c-0.3-0.3-0.8-0.3-1.1,0l-5.6,5.6l-1.4-1.4c-0.3-0.3-0.8-0.3-1.1,0l-0.7,0.7c-0.3,0.3-0.3,0.8,0,1.1l1.4,1.4l-4.2,4.2c-0.2,0.2-0.3,0.6-0.1,0.9l0.7,0.7c0.2,0.2,0.6,0.2,0.9-0.1l4.2-4.2l1.4,1.4c0.3,0.3,0.8,0.3,1.1,0l0.7-0.7c0.3-0.3,0.3-0.8,0-1.1l-1.4-1.4l5.6-5.6C22.8,2.3,22.8,1.8,22.5,1.5z M4.5,19.5l-2.8,2.8c-0.2,0.2-0.2,0.5,0,0.7s0.5,0.2,0.7,0L5.2,20.2L4.5,19.5z" />
